/**
 * hc_event_dispatcher.c
 *
 * HoloCanvas – Shared Event Dispatcher Implementation
 * ----------------------------------------------------
 * Implementation of the generic event dispatcher that centralizes Kafka
 * event consumption and dispatching logic across HoloCanvas services.
 *
 * Key features:
 *   - Hash map-based handler registry for O(1) event type lookup
 *   - Thread-safe operation with atomic flags for shutdown
 *   - Configurable Kafka consumer settings
 *   - JSON event parsing with type-based routing
 *
 * Copyright (c) 2024 The HoloCanvas Contributors
 * SPDX-License-Identifier: Apache-2.0
 */

#include "hc_event_dispatcher.h"

#include <errno.h>
#include <pthread.h>
#include <signal.h>
#include <stdatomic.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>

#include <jansson.h>
#include <librdkafka/rdkafka.h>

/* ============================================================================
 * Internal Constants
 * ============================================================================ */

#define DISPATCHER_LOG_PREFIX "[EventDispatcher] "
#define DEFAULT_POLL_TIMEOUT_MS 500
#define HANDLER_HASH_SIZE 64  /* Number of hash buckets */
#define MAX_EVENT_TYPE_LEN 128

/* ============================================================================
 * Internal Logging
 * ============================================================================ */

typedef enum {
    DISP_LOG_DEBUG = 0,
    DISP_LOG_INFO,
    DISP_LOG_WARN,
    DISP_LOG_ERROR
} disp_log_level_t;

static void disp_log(disp_log_level_t level, const char *fmt, ...) {
    static const char *LEVEL_STR[] = {"DEBUG", "INFO", "WARN", "ERROR"};

    char timebuf[32];
    struct timespec ts;
    clock_gettime(CLOCK_REALTIME, &ts);
    struct tm tm;
    localtime_r(&ts.tv_sec, &tm);
    strftime(timebuf, sizeof(timebuf), "%Y-%m-%d %H:%M:%S", &tm);

    FILE *out = (level >= DISP_LOG_ERROR) ? stderr : stdout;

    fprintf(out, "%s.%03ld %s%s: ", timebuf, ts.tv_nsec / 1000000,
            DISPATCHER_LOG_PREFIX, LEVEL_STR[level]);

    va_list ap;
    va_start(ap, fmt);
    vfprintf(out, fmt, ap);
    va_end(ap);

    fputc('\n', out);
}

#define LOG_DEBUG(...) disp_log(DISP_LOG_DEBUG, __VA_ARGS__)
#define LOG_INFO(...)  disp_log(DISP_LOG_INFO, __VA_ARGS__)
#define LOG_WARN(...)  disp_log(DISP_LOG_WARN, __VA_ARGS__)
#define LOG_ERROR(...) disp_log(DISP_LOG_ERROR, __VA_ARGS__)

/* ============================================================================
 * Internal Data Structures
 * ============================================================================ */

/**
 * Entry in the handler linked list for a single hash bucket.
 */
typedef struct HandlerEntry {
    char *event_type;               /**< Event type key (owned) */
    event_handler_func_t handler;   /**< Handler function pointer */
    struct HandlerEntry *next;      /**< Next entry in bucket chain */
} HandlerEntry;

/**
 * Hash map bucket for handler registry.
 */
typedef struct {
    HandlerEntry *head;             /**< Head of handler chain */
} HandlerBucket;

/**
 * Handler registry using a simple hash map.
 */
typedef struct {
    HandlerBucket buckets[HANDLER_HASH_SIZE];
    pthread_rwlock_t lock;          /**< Read-write lock for thread safety */
    size_t count;                   /**< Total number of registered handlers */
} HandlerRegistry;

/**
 * Internal dispatcher state.
 */
struct EventDispatcher {
    /* Kafka resources */
    rd_kafka_t *consumer;
    rd_kafka_conf_t *kafka_conf;
    rd_kafka_topic_partition_list_t *subscribed_topics;

    /* Configuration */
    char *brokers;
    char *topic;
    char *group_id;
    int poll_timeout_ms;

    /* Handler registry */
    HandlerRegistry registry;

    /* User context */
    void *user_context;

    /* Runtime state */
    atomic_bool running;
    atomic_bool should_stop;
};

/* Global dispatcher pointer for signal handler */
static EventDispatcher *g_signal_dispatcher = NULL;

/* ============================================================================
 * Hash Map Implementation
 * ============================================================================ */

/**
 * Simple DJB2 hash function for strings.
 */
static unsigned int hash_string(const char *str) {
    unsigned int hash = 5381;
    int c;
    while ((c = *str++)) {
        hash = ((hash << 5) + hash) + (unsigned int)c;
    }
    return hash;
}

static void registry_init(HandlerRegistry *reg) {
    memset(reg->buckets, 0, sizeof(reg->buckets));
    pthread_rwlock_init(&reg->lock, NULL);
    reg->count = 0;
}

static void registry_destroy(HandlerRegistry *reg) {
    pthread_rwlock_wrlock(&reg->lock);

    for (int i = 0; i < HANDLER_HASH_SIZE; i++) {
        HandlerEntry *entry = reg->buckets[i].head;
        while (entry) {
            HandlerEntry *next = entry->next;
            free(entry->event_type);
            free(entry);
            entry = next;
        }
        reg->buckets[i].head = NULL;
    }
    reg->count = 0;

    pthread_rwlock_unlock(&reg->lock);
    pthread_rwlock_destroy(&reg->lock);
}

static hc_error_t registry_add(HandlerRegistry *reg,
                               const char *event_type,
                               event_handler_func_t handler) {
    if (!event_type || !handler) {
        return HC_ERROR_PACK(HC_SUBSYS_COMMON, HC_SEV_ERROR, HC_EC_INVALID_ARGUMENT);
    }

    unsigned int idx = hash_string(event_type) % HANDLER_HASH_SIZE;

    HandlerEntry *entry = malloc(sizeof(HandlerEntry));
    if (!entry) {
        return HC_ERROR_PACK(HC_SUBSYS_COMMON, HC_SEV_ERROR, HC_EC_OUT_OF_MEMORY);
    }

    entry->event_type = strdup(event_type);
    if (!entry->event_type) {
        free(entry);
        return HC_ERROR_PACK(HC_SUBSYS_COMMON, HC_SEV_ERROR, HC_EC_OUT_OF_MEMORY);
    }
    entry->handler = handler;

    pthread_rwlock_wrlock(&reg->lock);

    /* Prepend to bucket chain */
    entry->next = reg->buckets[idx].head;
    reg->buckets[idx].head = entry;
    reg->count++;

    pthread_rwlock_unlock(&reg->lock);

    return HC_OK;
}

/**
 * Find and invoke all handlers for a given event type.
 * Returns the number of handlers invoked.
 */
static int registry_dispatch(HandlerRegistry *reg,
                             const char *event_type,
                             const char *payload,
                             size_t payload_len,
                             void *user_context) {
    unsigned int idx = hash_string(event_type) % HANDLER_HASH_SIZE;
    int count = 0;

    pthread_rwlock_rdlock(&reg->lock);

    HandlerEntry *entry = reg->buckets[idx].head;
    while (entry) {
        if (strcmp(entry->event_type, event_type) == 0) {
            hc_error_t rc = entry->handler(event_type, payload, payload_len, user_context);
            if (rc != HC_OK) {
                LOG_WARN("Handler for '%s' returned error: %s",
                         event_type, hc_error_str(rc));
            }
            count++;
        }
        entry = entry->next;
    }

    pthread_rwlock_unlock(&reg->lock);

    return count;
}

/* ============================================================================
 * Kafka Callbacks
 * ============================================================================ */

static void kafka_log_cb(const rd_kafka_t *rk, int level,
                         const char *fac, const char *buf) {
    (void)rk;
    (void)fac;
    if (level <= 3) {
        LOG_ERROR("rdkafka: %s", buf);
    } else if (level <= 5) {
        LOG_WARN("rdkafka: %s", buf);
    } else {
        LOG_DEBUG("rdkafka: %s", buf);
    }
}

static void kafka_error_cb(rd_kafka_t *rk, int err,
                           const char *reason, void *opaque) {
    (void)rk;
    (void)opaque;
    LOG_ERROR("Kafka error (%d): %s", err, reason);
}

/* ============================================================================
 * Event Processing
 * ============================================================================ */

/**
 * Parse JSON message and extract event type and payload.
 * Expected format: { "type": "EVENT_TYPE", "payload": {...} }
 */
static hc_error_t process_message(EventDispatcher *disp,
                                  const void *data,
                                  size_t len) {
    json_error_t jerr;
    json_t *root = json_loadb((const char *)data, len, 0, &jerr);
    if (!root) {
        LOG_WARN("JSON parse error at line %d: %s", jerr.line, jerr.text);
        return HC_ERROR_PACK(HC_SUBSYS_COMMON, HC_SEV_WARNING, HC_EC_DATA_CORRUPT);
    }

    /* Extract event type */
    json_t *type_node = json_object_get(root, "type");
    if (!json_is_string(type_node)) {
        LOG_WARN("Event missing 'type' field or not a string");
        json_decref(root);
        return HC_ERROR_PACK(HC_SUBSYS_COMMON, HC_SEV_WARNING, HC_EC_DATA_CORRUPT);
    }

    const char *event_type = json_string_value(type_node);

    /* Extract payload - pass the entire payload subtree as JSON string */
    json_t *payload_node = json_object_get(root, "payload");
    char *payload_str = NULL;
    size_t payload_len = 0;

    if (payload_node) {
        payload_str = json_dumps(payload_node, JSON_COMPACT);
        if (payload_str) {
            payload_len = strlen(payload_str);
        }
    }

    /* If no payload, use the raw message */
    if (!payload_str) {
        payload_str = strndup((const char *)data, len);
        payload_len = len;
    }

    LOG_DEBUG("Processing event: type=%s, payload_len=%zu", event_type, payload_len);

    /* Dispatch to registered handlers */
    int handler_count = registry_dispatch(&disp->registry,
                                          event_type,
                                          payload_str,
                                          payload_len,
                                          disp->user_context);

    if (handler_count == 0) {
        LOG_DEBUG("No handlers registered for event type '%s'", event_type);
    } else {
        LOG_DEBUG("Dispatched '%s' to %d handler(s)", event_type, handler_count);
    }

    free(payload_str);
    json_decref(root);

    return HC_OK;
}

/* ============================================================================
 * Signal Handling
 * ============================================================================ */

static void dispatcher_signal_handler(int sig) {
    (void)sig;
    if (g_signal_dispatcher) {
        event_dispatcher_stop(g_signal_dispatcher);
    }
}

/* ============================================================================
 * Public API Implementation
 * ============================================================================ */

EventDispatcher *event_dispatcher_create(const EventDispatcherConfig *config) {
    if (!config || !config->kafka_brokers || !config->topic || !config->group_id) {
        LOG_ERROR("Invalid configuration: missing required parameters");
        return NULL;
    }

    EventDispatcher *disp = calloc(1, sizeof(EventDispatcher));
    if (!disp) {
        LOG_ERROR("Failed to allocate dispatcher");
        return NULL;
    }

    /* Copy configuration */
    disp->brokers = strdup(config->kafka_brokers);
    disp->topic = strdup(config->topic);
    disp->group_id = strdup(config->group_id);
    disp->poll_timeout_ms = config->poll_timeout_ms > 0
                            ? config->poll_timeout_ms
                            : DEFAULT_POLL_TIMEOUT_MS;
    disp->user_context = config->user_context;

    if (!disp->brokers || !disp->topic || !disp->group_id) {
        LOG_ERROR("Failed to copy configuration strings");
        goto cleanup;
    }

    /* Initialize handler registry */
    registry_init(&disp->registry);

    /* Configure Kafka consumer */
    char errstr[512];
    disp->kafka_conf = rd_kafka_conf_new();

    if (rd_kafka_conf_set(disp->kafka_conf, "bootstrap.servers",
                          disp->brokers, errstr, sizeof(errstr)) != RD_KAFKA_CONF_OK) {
        LOG_ERROR("Kafka config error (brokers): %s", errstr);
        goto cleanup;
    }

    if (rd_kafka_conf_set(disp->kafka_conf, "group.id",
                          disp->group_id, errstr, sizeof(errstr)) != RD_KAFKA_CONF_OK) {
        LOG_ERROR("Kafka config error (group.id): %s", errstr);
        goto cleanup;
    }

    /* Set auto-commit based on config */
    const char *auto_commit = config->enable_auto_commit ? "true" : "false";
    rd_kafka_conf_set(disp->kafka_conf, "enable.auto.commit", auto_commit, NULL, 0);
    rd_kafka_conf_set(disp->kafka_conf, "auto.offset.reset", "earliest", NULL, 0);

    /* Set callbacks */
    rd_kafka_conf_set_log_cb(disp->kafka_conf, kafka_log_cb);
    rd_kafka_conf_set_error_cb(disp->kafka_conf, kafka_error_cb);

    /* Create consumer */
    disp->consumer = rd_kafka_new(RD_KAFKA_CONSUMER, disp->kafka_conf,
                                  errstr, sizeof(errstr));
    if (!disp->consumer) {
        LOG_ERROR("Failed to create Kafka consumer: %s", errstr);
        goto cleanup;
    }

    /* Configuration is now owned by consumer */
    disp->kafka_conf = NULL;

    rd_kafka_poll_set_consumer(disp->consumer);

    /* Subscribe to topic */
    disp->subscribed_topics = rd_kafka_topic_partition_list_new(1);
    rd_kafka_topic_partition_list_add(disp->subscribed_topics, disp->topic,
                                      RD_KAFKA_PARTITION_UA);

    rd_kafka_resp_err_t err = rd_kafka_subscribe(disp->consumer, disp->subscribed_topics);
    if (err != RD_KAFKA_RESP_ERR_NO_ERROR) {
        LOG_ERROR("Failed to subscribe to topic '%s': %s",
                  disp->topic, rd_kafka_err2str(err));
        goto cleanup;
    }

    atomic_store(&disp->running, false);
    atomic_store(&disp->should_stop, false);

    LOG_INFO("Event dispatcher created (brokers=%s, topic=%s, group=%s)",
             disp->brokers, disp->topic, disp->group_id);

    return disp;

cleanup:
    event_dispatcher_destroy(disp);
    return NULL;
}

hc_error_t event_dispatcher_register_handler(EventDispatcher *dispatcher,
                                              const char *event_type,
                                              event_handler_func_t handler) {
    if (!dispatcher) {
        return HC_ERROR_PACK(HC_SUBSYS_COMMON, HC_SEV_ERROR, HC_EC_INVALID_ARGUMENT);
    }

    hc_error_t rc = registry_add(&dispatcher->registry, event_type, handler);
    if (rc == HC_OK) {
        LOG_INFO("Registered handler for event type '%s'", event_type);
    }

    return rc;
}

void event_dispatcher_run(EventDispatcher *dispatcher) {
    if (!dispatcher || !dispatcher->consumer) {
        LOG_ERROR("Cannot run: dispatcher not properly initialized");
        return;
    }

    if (atomic_load(&dispatcher->running)) {
        LOG_WARN("Dispatcher is already running");
        return;
    }

    atomic_store(&dispatcher->running, true);
    atomic_store(&dispatcher->should_stop, false);

    LOG_INFO("Event dispatcher starting main loop");

    while (!atomic_load(&dispatcher->should_stop)) {
        rd_kafka_message_t *rkmsg = rd_kafka_consumer_poll(dispatcher->consumer,
                                                           dispatcher->poll_timeout_ms);
        if (!rkmsg) {
            continue; /* Timeout - poll again */
        }

        if (rkmsg->err) {
            if (rkmsg->err == RD_KAFKA_RESP_ERR__PARTITION_EOF) {
                /* End of partition - not an error */
                rd_kafka_message_destroy(rkmsg);
                continue;
            }
            LOG_WARN("Kafka consume error: %s", rd_kafka_message_errstr(rkmsg));
            rd_kafka_message_destroy(rkmsg);
            continue;
        }

        /* Process the message */
        process_message(dispatcher, rkmsg->payload, rkmsg->len);

        rd_kafka_message_destroy(rkmsg);
    }

    atomic_store(&dispatcher->running, false);
    LOG_INFO("Event dispatcher main loop exited");
}

void event_dispatcher_stop(EventDispatcher *dispatcher) {
    if (dispatcher) {
        LOG_INFO("Stopping event dispatcher...");
        atomic_store(&dispatcher->should_stop, true);
    }
}

void event_dispatcher_destroy(EventDispatcher *dispatcher) {
    if (!dispatcher) {
        return;
    }

    LOG_INFO("Destroying event dispatcher...");

    /* Stop if running */
    event_dispatcher_stop(dispatcher);

    /* Wait briefly for run loop to exit */
    for (int i = 0; i < 50 && atomic_load(&dispatcher->running); i++) {
        struct timespec ts = {.tv_sec = 0, .tv_nsec = 100000000}; /* 100ms */
        nanosleep(&ts, NULL);
    }

    /* Close Kafka consumer */
    if (dispatcher->consumer) {
        rd_kafka_consumer_close(dispatcher->consumer);
        rd_kafka_destroy(dispatcher->consumer);
    }

    if (dispatcher->kafka_conf) {
        rd_kafka_conf_destroy(dispatcher->kafka_conf);
    }

    if (dispatcher->subscribed_topics) {
        rd_kafka_topic_partition_list_destroy(dispatcher->subscribed_topics);
    }

    /* Destroy handler registry */
    registry_destroy(&dispatcher->registry);

    /* Free configuration strings */
    free(dispatcher->brokers);
    free(dispatcher->topic);
    free(dispatcher->group_id);

    /* Clear signal handler reference if this was the registered dispatcher */
    if (g_signal_dispatcher == dispatcher) {
        g_signal_dispatcher = NULL;
    }

    free(dispatcher);
    LOG_INFO("Event dispatcher destroyed");
}

void *event_dispatcher_get_context(const EventDispatcher *dispatcher) {
    return dispatcher ? dispatcher->user_context : NULL;
}

bool event_dispatcher_is_running(const EventDispatcher *dispatcher) {
    return dispatcher ? atomic_load(&dispatcher->running) : false;
}

void event_dispatcher_install_signal_handlers(EventDispatcher *dispatcher) {
    if (!dispatcher) {
        return;
    }

    g_signal_dispatcher = dispatcher;

    struct sigaction sa = {
        .sa_handler = dispatcher_signal_handler,
        .sa_flags = 0
    };
    sigemptyset(&sa.sa_mask);

    sigaction(SIGINT, &sa, NULL);
    sigaction(SIGTERM, &sa, NULL);

    LOG_INFO("Signal handlers installed for SIGINT and SIGTERM");
}

/* End of file */

/*
 * HoloCanvas Governance Hall – Main Service Entrypoint (Refactored)
 *
 * Project      : HoloCanvas – A Micro-Gallery Blockchain for Generative Artifacts
 * Service      : governance_hall
 * File         : src/main.c
 * Description  :
 *      Governance-Hall is the DAO brain of HoloCanvas. This refactored version
 *      uses the shared EventDispatcher module for Kafka event consumption,
 *      eliminating duplicated boilerplate code.
 *
 *      The service now:
 *          • Uses event_dispatcher_create() to set up Kafka connection
 *          • Registers specific event handlers for governance events
 *          • Delegates event loop to event_dispatcher_run()
 */

#define _POSIX_C_SOURCE 200809L

#include <errno.h>
#include <signal.h>
#include <stdatomic.h>
#include <stdbool.h>
#include <stdint.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <pthread.h>
#include <unistd.h>

#include "uthash.h"

/* Include the shared event dispatcher */
#include "shared/event_dispatcher/hc_event_dispatcher.h"

/* -------------------------------------------------------------------------- */
/*                               Build-time Info                              */
/* -------------------------------------------------------------------------- */
#define GOV_HALL_VERSION "1.3.0"
#define BUILD_TIMESTAMP  __DATE__ " " __TIME__

/* -------------------------------------------------------------------------- */
/*                                 Logging                                    */
/* -------------------------------------------------------------------------- */
typedef enum {
    LOG_DEBUG,
    LOG_INFO,
    LOG_WARN,
    LOG_ERROR,
    LOG_FATAL
} log_level_t;

static log_level_t g_log_level = LOG_INFO;

static const char *log_level_str(log_level_t lvl)
{
    switch (lvl) {
    case LOG_DEBUG: return "DEBUG";
    case LOG_INFO:  return "INFO ";
    case LOG_WARN:  return "WARN ";
    case LOG_ERROR: return "ERROR";
    case LOG_FATAL: return "FATAL";
    default:        return "?????";
    }
}

static void log_internal(log_level_t lvl,
                         const char *file,
                         int line,
                         const char *fmt, ...)
{
    if (lvl < g_log_level) {
        return;
    }

    struct timespec ts;
    clock_gettime(CLOCK_REALTIME, &ts);

    struct tm tm;
    localtime_r(&ts.tv_sec, &tm);

    char ts_buf[64];
    strftime(ts_buf, sizeof ts_buf, "%Y-%m-%d %H:%M:%S", &tm);

    fprintf((lvl >= LOG_ERROR) ? stderr : stdout,
            "%s.%03ld [%s] %s:%d: ",
            ts_buf, ts.tv_nsec / 1000000,
            log_level_str(lvl),
            file, line);

    va_list ap;
    va_start(ap, fmt);
    vfprintf((lvl >= LOG_ERROR) ? stderr : stdout, fmt, ap);
    va_end(ap);

    fputc('\n', (lvl >= LOG_ERROR) ? stderr : stdout);

    if (lvl == LOG_FATAL) {
        abort();
    }
}

#define LOGD(...) log_internal(LOG_DEBUG, __FILE__, __LINE__, __VA_ARGS__)
#define LOGI(...) log_internal(LOG_INFO,  __FILE__, __LINE__, __VA_ARGS__)
#define LOGW(...) log_internal(LOG_WARN,  __FILE__, __LINE__, __VA_ARGS__)
#define LOGE(...) log_internal(LOG_ERROR, __FILE__, __LINE__, __VA_ARGS__)
#define LOGF(...) log_internal(LOG_FATAL, __FILE__, __LINE__, __VA_ARGS__)

/* -------------------------------------------------------------------------- */
/*                         Governance Proposal State                          */
/* -------------------------------------------------------------------------- */

typedef enum {
    PROPOSAL_DRAFT = 0,
    PROPOSAL_VOTING,
    PROPOSAL_ACCEPTED,
    PROPOSAL_REJECTED,
    PROPOSAL_EXECUTED
} proposal_state_t;

typedef struct governance_proposal {
    char id[64];
    proposal_state_t state;
    uint64_t yes_votes;
    uint64_t no_votes;
    time_t created_at;
    time_t voting_deadline;
    UT_hash_handle hh;
} governance_proposal_t;

/* In-memory key-value store of proposals */
static governance_proposal_t *g_proposals = NULL;
static pthread_rwlock_t g_prop_lock = PTHREAD_RWLOCK_INITIALIZER;

/* Lookup or create a proposal record */
static governance_proposal_t *
proposal_get_or_create(const char *id)
{
    governance_proposal_t *p = NULL;
    pthread_rwlock_rdlock(&g_prop_lock);
    HASH_FIND_STR(g_proposals, id, p);
    pthread_rwlock_unlock(&g_prop_lock);

    if (p) {
        return p;
    }

    pthread_rwlock_wrlock(&g_prop_lock);
    HASH_FIND_STR(g_proposals, id, p);
    if (!p) {
        p = calloc(1, sizeof *p);
        if (!p) {
            pthread_rwlock_unlock(&g_prop_lock);
            LOGE("Memory allocation failed for proposal '%s'", id);
            return NULL;
        }
        strncpy(p->id, id, sizeof p->id - 1);
        p->created_at = time(NULL);
        p->state      = PROPOSAL_DRAFT;
        HASH_ADD_STR(g_proposals, id, p);
        LOGI("Created new proposal %s", id);
    }
    pthread_rwlock_unlock(&g_prop_lock);
    return p;
}

static void proposal_try_finalize(governance_proposal_t *p)
{
    if (p->state != PROPOSAL_VOTING) {
        return;
    }

    time_t now = time(NULL);
    if (now < p->voting_deadline) {
        return;
    }

    p->state = (p->yes_votes > p->no_votes)
                 ? PROPOSAL_ACCEPTED
                 : PROPOSAL_REJECTED;

    LOGI("Proposal %s finalized as %s (yes=%" PRIu64 ", no=%" PRIu64 ")",
         p->id,
         (p->state == PROPOSAL_ACCEPTED) ? "ACCEPTED" : "REJECTED",
         p->yes_votes, p->no_votes);
}

/* -------------------------------------------------------------------------- */
/*                     Event Handlers (Using New Signature)                   */
/* -------------------------------------------------------------------------- */

/**
 * Handler for PROPOSAL_CREATE events.
 */
hc_error_t handle_proposal_create(const char *event_type,
                                   const char *payload,
                                   size_t payload_len,
                                   void *user_context)
{
    (void)event_type;
    (void)payload_len;
    (void)user_context;

    /* Parse the JSON payload to extract id and voting_deadline */
    json_error_t jerr;
    json_t *root = json_loads(payload, 0, &jerr);
    if (!root) {
        LOGW("Failed to parse PROPOSAL_CREATE payload: %s", jerr.text);
        return HC_ERROR_PACK(HC_SUBSYS_GOVERNANCE, HC_SEV_WARNING, HC_EC_DATA_CORRUPT);
    }

    const char *id = json_string_value(json_object_get(root, "id"));
    json_t *deadline_node = json_object_get(root, "voting_deadline");

    if (!id) {
        LOGW("PROPOSAL_CREATE missing 'id' field");
        json_decref(root);
        return HC_ERROR_PACK(HC_SUBSYS_GOVERNANCE, HC_SEV_WARNING, HC_EC_INVALID_ARGUMENT);
    }

    governance_proposal_t *p = proposal_get_or_create(id);
    if (p) {
        p->state = PROPOSAL_VOTING;
        if (json_is_integer(deadline_node)) {
            p->voting_deadline = (time_t)json_integer_value(deadline_node);
        }
        LOGI("Proposal %s entered VOTING state (deadline=%lu)",
             p->id, (unsigned long)p->voting_deadline);
    }

    json_decref(root);
    return HC_OK;
}

/**
 * Handler for VOTE_CAST events.
 */
hc_error_t handle_vote_cast(const char *event_type,
                             const char *payload,
                             size_t payload_len,
                             void *user_context)
{
    (void)event_type;
    (void)payload_len;
    (void)user_context;

    json_error_t jerr;
    json_t *root = json_loads(payload, 0, &jerr);
    if (!root) {
        LOGW("Failed to parse VOTE_CAST payload: %s", jerr.text);
        return HC_ERROR_PACK(HC_SUBSYS_GOVERNANCE, HC_SEV_WARNING, HC_EC_DATA_CORRUPT);
    }

    const char *id = json_string_value(json_object_get(root, "id"));
    const char *vote = json_string_value(json_object_get(root, "vote"));

    if (!id || !vote) {
        LOGW("VOTE_CAST missing required fields");
        json_decref(root);
        return HC_ERROR_PACK(HC_SUBSYS_GOVERNANCE, HC_SEV_WARNING, HC_EC_INVALID_ARGUMENT);
    }

    governance_proposal_t *p = proposal_get_or_create(id);
    if (!p) {
        json_decref(root);
        return HC_ERROR_PACK(HC_SUBSYS_GOVERNANCE, HC_SEV_ERROR, HC_EC_OUT_OF_MEMORY);
    }

    if (p->state != PROPOSAL_VOTING) {
        LOGW("Vote ignored for non-voting proposal %s", p->id);
        json_decref(root);
        return HC_OK;
    }

    bool vote_yes = (strcmp(vote, "yes") == 0);
    if (vote_yes)
        p->yes_votes++;
    else
        p->no_votes++;

    LOGD("Vote registered on %s → yes=%" PRIu64 ", no=%" PRIu64,
         p->id, p->yes_votes, p->no_votes);

    json_decref(root);
    return HC_OK;
}

/**
 * Handler for FINALIZE_REQ events.
 */
hc_error_t handle_finalize_request(const char *event_type,
                                    const char *payload,
                                    size_t payload_len,
                                    void *user_context)
{
    (void)event_type;
    (void)payload_len;
    (void)user_context;

    json_error_t jerr;
    json_t *root = json_loads(payload, 0, &jerr);
    if (!root) {
        LOGW("Failed to parse FINALIZE_REQ payload: %s", jerr.text);
        return HC_ERROR_PACK(HC_SUBSYS_GOVERNANCE, HC_SEV_WARNING, HC_EC_DATA_CORRUPT);
    }

    const char *id = json_string_value(json_object_get(root, "id"));
    if (!id) {
        LOGW("FINALIZE_REQ missing 'id' field");
        json_decref(root);
        return HC_ERROR_PACK(HC_SUBSYS_GOVERNANCE, HC_SEV_WARNING, HC_EC_INVALID_ARGUMENT);
    }

    governance_proposal_t *p = NULL;
    pthread_rwlock_rdlock(&g_prop_lock);
    HASH_FIND_STR(g_proposals, id, p);
    pthread_rwlock_unlock(&g_prop_lock);

    if (!p) {
        LOGW("Finalize requested for unknown proposal %s", id);
    } else {
        proposal_try_finalize(p);
    }

    json_decref(root);
    return HC_OK;
}

