int main(void)
{
    LOG_INFO("Starting %s v%s", SERVICE_NAME, VERSION_STRING);

    config_t cfg;
    load_config(&cfg);
    LOG_INFO("Config: Kafka[%s/%s] Ledger[%s] Workers[%d]",
             cfg.kafka_broker, cfg.kafka_topic,
             cfg.ledger_endpoint, cfg.workers);

    bqueue_t queue;
    bq_init(&queue);

    /* Create service context for handlers */
    service_context_t svc_ctx = {
        .queue = &queue,
        .cfg = &cfg
    };

    /* Create the event dispatcher */
    EventDispatcherConfig disp_config = {
        .kafka_brokers = cfg.kafka_broker,
        .topic = cfg.kafka_topic,
        .group_id = cfg.kafka_group_id,
        .user_context = &svc_ctx,
        .poll_timeout_ms = 250,
        .enable_auto_commit = true
    };

    EventDispatcher *dispatcher = event_dispatcher_create(&disp_config);
    if (!dispatcher) {
        LOG_ERROR("Failed to create event dispatcher");
        return EXIT_FAILURE;
    }

    /* Register event handlers */
    event_dispatcher_register_handler(dispatcher, "MINT_REQUEST", handle_mint_request);
    event_dispatcher_register_handler(dispatcher, "BID", handle_bid);
    event_dispatcher_register_handler(dispatcher, "GOVERNANCE_VOTE", handle_governance_vote);
    event_dispatcher_register_handler(dispatcher, "ORACLE_FEED", handle_oracle_feed);

    /* Install signal handlers */
    event_dispatcher_install_signal_handlers(dispatcher);

    /* Spawn worker threads */
    pthread_t workers[MAX_WORKERS];
    worker_arg_t warg[MAX_WORKERS];
    for (int i = 0; i < cfg.workers; ++i) {
        warg[i].queue = &queue;
        warg[i].cfg   = &cfg;
        warg[i].idx   = i;
        if (pthread_create(&workers[i], NULL, worker_loop, &warg[i]) != 0) {
            LOG_ERROR("Failed to create worker thread");
            atomic_store(&g_shutdown_flag, true);
            break;
        }
    }

    LOG_INFO("Mint-Factory ready, starting event loop...");

    /* Run the event loop (blocks until stopped) */
    event_dispatcher_run(dispatcher);

    /* Shutdown sequence */
    LOG_INFO("Shutdown requested – waiting for threads");
    atomic_store(&g_shutdown_flag, true);

    /* Wake queues and join threads */
    pthread_mutex_lock(&queue.mtx);
    pthread_cond_broadcast(&queue.not_empty);
    pthread_cond_broadcast(&queue.not_full);
    pthread_mutex_unlock(&queue.mtx);

    for (int i = 0; i < cfg.workers; ++i) {
        pthread_join(workers[i], NULL);
    }

    event_dispatcher_destroy(dispatcher);

    LOG_INFO("%s terminated gracefully", SERVICE_NAME);
    return 0;
}

