   345→    event_handler_t *handler = arg;
   346→    const int timeout_ms = 500;
   347→
   348→    while (handler->running) {
   349→        rd_kafka_message_t *rkmsg = rd_kafka_consumer_poll(handler->rk,
   350→                                                           timeout_ms);
   351→        if (!rkmsg) continue;
   352→
   353→        if (rkmsg->err) {
   354→            if (rkmsg->err == RD_KAFKA_RESP_ERR__PARTITION_EOF) {
   355→                rd_kafka_message_destroy(rkmsg);
   356→                continue;
   357→            }
   358→            LOG_WARN("Kafka error: %s", rd_kafka_message_errstr(rkmsg));
   359→            rd_kafka_message_destroy(rkmsg);
   360→            continue;
   361→        }
   362→
   363→        /* Parse message as JSON */
   364→        json_error_t jerr;
   365→        json_t *root = json_loadb((const char *)rkmsg->payload,
   366→                                  rkmsg->len, 0, &jerr);
   367→        if (!root) {
   368→            LOG_WARN("JSON parse error at line %d: %s", jerr.line, jerr.text);
   369→            rd_kafka_message_destroy(rkmsg);
   370→            continue;
   371→        }
   372→
   373→        /* Validate schema */
   374→        json_t *type_js = json_object_get(root, "type");
   375→        json_t *payload = json_object_get(root, "payload");
   376→        json_t *sig     = json_object_get(root, "sig");
   377→        json_t *ts      = json_object_get(root, "timestamp");
   378→
   379→        if (!json_is_string(type_js) || !json_is_object(payload) ||
   380→            !json_is_string(sig)     || !json_is_integer(ts)) {
   381→            LOG_WARN("Invalid event schema, dropping.");
   382→            json_decref(root);
   383→            rd_kafka_message_destroy(rkmsg);
   384→            continue;
   385→        }
   386→
   387→        /* Cryptographic validation */
   388→        if (!verify_event_signature(root, handler->governance_pub)) {
   389→            LOG_WARN("Signature verification failed, dropping event.");
   390→            json_decref(root);
   391→            rd_kafka_message_destroy(rkmsg);
   392→            continue;
   393→        }
   394→
   395→        /* Dispatch */
   396→        const char *type_str = json_string_value(type_js);
   397→        dispatch_event(handler, type_str, payload);
   398→
   399→        json_decref(root);
   400→        rd_kafka_message_destroy(rkmsg);
   401→    }
   402→
   403→    return NULL;
   404→}
