   440→
   441→/* Canonicalize event by serializing `type`+`payload`+`timestamp` */
   442→static char *canonicalize_event(const json_t *root, size_t *out_len)
   443→{
   444→    json_t *type     = json_object_get(root, "type");
   445→    json_t *payload  = json_object_get(root, "payload");
   446→    json_t *ts       = json_object_get(root, "timestamp");
   447→
   448→    /* Build new object in predictable order */
   449→    json_t *canon = json_pack("{s:o,s:o,s:o}",
   450→                              "type", type,
   451→                              "payload", payload,
   452→                              "timestamp", ts);
   453→
   454→    char *dump = json_dumps(canon, JSON_COMPACT|JSON_SORT_KEYS);
   455→    *out_len = strlen(dump);
   456→    json_decref(canon);
   457→    return dump;
   458→}
   459→
   460→static bool verify_event_signature(const json_t *root, EVP_PKEY *pubkey)
   461→{
   462→    json_t *sig_js = json_object_get(root, "sig");
   463→    if (!json_is_string(sig_js)) return false;
   464→
   465→    const char *sig_b64 = json_string_value(sig_js);
   466→    size_t sig_len = 0;
   467→
   468→    /* Base64 decode */
   469→    BIO *b64 = BIO_new(BIO_f_base64());
   470→    BIO_set_flags(b64, BIO_FLAGS_BASE64_NO_NL);
   471→    BIO *mem = BIO_new_mem_buf(sig_b64, -1);
   472→    BIO_push(b64, mem);
   473→
   474→    uint8_t sig_buf[512]; /* Should accommodate 4096-bit RSA */
   475→    sig_len = BIO_read(b64, sig_buf, sizeof sig_buf);
   476→    BIO_free_all(b64);
   477→
   478→    if (sig_len <= 0) {
   479→        LOG_WARN("Signature base64 decode failed");
   480→        return false;
   481→    }
   482→
   483→    size_t msg_len = 0;
   484→    char *msg = canonicalize_event(root, &msg_len);
   485→
   486→    bool ok = false;
   487→    EVP_MD_CTX *mdctx = EVP_MD_CTX_new();
   488→    if (EVP_DigestVerifyInit(mdctx, NULL, EVP_sha256(), NULL, pubkey) == 1 &&
   489→        EVP_DigestVerifyUpdate(mdctx, msg, msg_len) == 1 &&
   490→        EVP_DigestVerifyFinal(mdctx, sig_buf, sig_len) == 1) {
   491→        ok = true;
   492→    }
   493→
   494→    if (!ok) {
   495→        LOG_WARN("EVP_DigestVerify failed: %s",
   496→                 ERR_error_string(ERR_get_error(), NULL));
   497→    }
   498→
   499→    free(msg);
   500→    EVP_MD_CTX_free(mdctx);
   501→    return ok;
   502→}
