    54→/*                                 Logging                                    */
    55→/* -------------------------------------------------------------------------- */
    56→typedef enum {
    57→    LOG_DEBUG,
    58→    LOG_INFO,
    59→    LOG_WARN,
    60→    LOG_ERROR,
    61→    LOG_FATAL
    62→} log_level_t;
    63→
    64→/* The log level can be overridden via the GOV_HALL_LOG_LEVEL env variable */
