    66→
    67→static const char *log_level_str(log_level_t lvl)
    68→{
    69→    switch (lvl) {
    70→    case LOG_DEBUG: return "DEBUG";
    71→    case LOG_INFO:  return "INFO ";
    72→    case LOG_WARN:  return "WARN ";
    73→    case LOG_ERROR: return "ERROR";
    74→    case LOG_FATAL: return "FATAL";
    75→    default:        return "?????";
    76→    }
    77→}
    78→
    79→static void log_internal(log_level_t lvl,
    80→                         const char *file,
    81→                         int line,
    82→                         const char *fmt, ...)
    83→{
    84→    if (lvl < g_log_level) {
    85→        return;
    86→    }
    87→
    88→    struct timespec ts;
    89→    clock_gettime(CLOCK_REALTIME, &ts);
    90→
    91→    struct tm tm;
    92→    localtime_r(&ts.tv_sec, &tm);
