   103→    va_list ap;
   104→    va_start(ap, fmt);
   105→    vfprintf((lvl >= LOG_ERROR) ? stderr : stdout, fmt, ap);
   106→    va_end(ap);
   107→
   108→    fputc('\n', (lvl >= LOG_ERROR) ? stderr : stdout);
   109→
   110→    if (lvl == LOG_FATAL) {
   111→        abort();
   112→    }
   113→}
