   121→/* -------------------------------------------------------------------------- */
   122→/*                         Governance Proposal State                          */
   123→/* -------------------------------------------------------------------------- */
   124→
   125→typedef enum {
   126→    PROPOSAL_DRAFT = 0,
   127→    PROPOSAL_VOTING,
   128→    PROPOSAL_ACCEPTED,
   129→    PROPOSAL_REJECTED,
   130→    PROPOSAL_EXECUTED
   131→} proposal_state_t;
   132→
   133→typedef struct governance_proposal {
   134→    char id[64];                /* unique sha-256/uuid string */
   135→    proposal_state_t state;
   136→    uint64_t yes_votes;
   137→    uint64_t no_votes;
   138→    time_t created_at;
   139→    time_t voting_deadline;     /* epoch seconds */
   140→    UT_hash_handle hh;          /* makes this struct hashable */
   141→} governance_proposal_t;
   142→
   143→/* In-memory key-value store of proposals */
   144→static governance_proposal_t *g_proposals = NULL;
   145→/* Protects g_proposals against concurrent reads/writes */
   146→static pthread_rwlock_t g_prop_lock = PTHREAD_RWLOCK_INITIALIZER;
   147→
   148→/* Lookup or create a proposal record */
   149→static governance_proposal_t *
   150→proposal_get_or_create(const char *id)
   151→{
   152→    governance_proposal_t *p = NULL;
   153→    pthread_rwlock_rdlock(&g_prop_lock);
   154→    HASH_FIND_STR(g_proposals, id, p);
   155→    pthread_rwlock_unlock(&g_prop_lock);
   156→
   157→    if (p) {
   158→        return p;
   159→    }
   160→
   161→    /* Not found – upgrade to write lock and allocate */
   162→    pthread_rwlock_wrlock(&g_prop_lock);
   163→    HASH_FIND_STR(g_proposals, id, p);
   164→    if (!p) {
   165→        p = calloc(1, sizeof *p);
   166→        if (!p) {
   167→            pthread_rwlock_unlock(&g_prop_lock);
   168→            LOGE("Memory allocation failed for proposal '%s'", id);
   169→            return NULL;
   170→        }
   171→        strncpy(p->id, id, sizeof p->id - 1);
   172→        p->created_at = time(NULL);
   173→        p->state      = PROPOSAL_DRAFT;
   174→        HASH_ADD_STR(g_proposals, id, p);
   175→        LOGI("Created new proposal %s", id);
   176→    }
   177→    pthread_rwlock_unlock(&g_prop_lock);
   178→    return p;
   179→}
