   181→/* Apply proposal finite-state transitions */
   182→static void proposal_try_finalize(governance_proposal_t *p)
   183→{
   184→    if (p->state != PROPOSAL_VOTING) {
   185→        return;
   186→    }
   187→
   188→    time_t now = time(NULL);
   189→    if (now < p->voting_deadline) {
   190→        return;
   191→    }
   192→
   193→    /* Time is up – tally */
   194→    p->state = (p->yes_votes > p->no_votes)
   195→                 ? PROPOSAL_ACCEPTED
   196→                 : PROPOSAL_REJECTED;
   197→
   198→    LOGI("Proposal %s finalized as %s (yes=%" PRIu64 ", no=%" PRIu64 ")",
   199→         p->id,
   200→         (p->state == PROPOSAL_ACCEPTED) ? "ACCEPTED" : "REJECTED",
   201→         p->yes_votes, p->no_votes);
   202→}
