   208→/*
   209→ * In production we ingest binary protobuf payloads from Kafka.  For purposes of
   210→ * this sample we accept a line-oriented JSON subset coming from stdin, Kafka,
   211→ * or a test file.  Each line is one event:
   212→ *
   213→ *  { "type":"PROPOSAL_CREATE", "id":"abc", "voting_deadline":1660000000 }
   214→ *  { "type":"VOTE_CAST", "id":"abc", "vote":"yes" }
   215→ *
   216→ * This rudimentary parser keeps the demo self-contained without pulling in a
   217→ * heavyweight JSON stack.  It is NOT robust and must be replaced for prod.
   218→ */
   219→
   220→typedef enum {
   221→    EVT_NONE = 0,
   222→    EVT_PROPOSAL_CREATE,
   223→    EVT_VOTE_CAST,
   224→    EVT_FINALIZE_REQ
   225→} event_type_t;
   226→
   227→typedef struct {
   228→    event_type_t type;
   229→    char id[64];
   230→    uint64_t voting_deadline;   /* for CREATE */
   231→    bool vote_yes;              /* for VOTE */
