   233→
   234→static void trim(char *s)
   235→{
   236→    char *p = s;
   237→    size_t len = strlen(s);
   238→    while (len && (s[len - 1] == '\n' || s[len - 1] == '\r' || s[len - 1] == ' '))
   239→        s[--len] = '\0';
   240→    while (*p == ' ' || *p == '\t')
   241→        ++p;
   242→    if (p != s)
   243→        memmove(s, p, strlen(p) + 1);
   244→}
   245→
   246→/* Extremely naive key search */
   247→static const char *json_get_value(const char *json, const char *key, char *buf, size_t buf_sz)
   248→{
   249→    char pattern[64];
   250→    snprintf(pattern, sizeof pattern, "\"%s\":\"", key);
   251→    const char *p = strstr(json, pattern);
   252→    if (!p) return NULL;
   253→    p += strlen(pattern);
   254→    const char *q = strchr(p, '"');
   255→    if (!q) return NULL;
   256→    size_t len = (size_t)(q - p);
   257→    if (len >= buf_sz) len = buf_sz - 1;
   258→    memcpy(buf, p, len);
   259→    buf[len] = '\0';
   260→    return buf;
   261→}
   262→
   263→static bool json_get_uint64(const char *json, const char *key, uint64_t *out)
   264→{
   265→    char pattern[64];
   266→    snprintf(pattern, sizeof pattern, "\"%s\":", key);
   267→    const char *p = strstr(json, pattern);
   268→    if (!p) return false;
   269→    p += strlen(pattern);
   270→    *out = strtoull(p, NULL, 10);
   271→    return true;
   272→}
   273→
   274→static event_type_t parse_event_type(const char *json)
   275→{
   276→    char type[32];
   277→    if (!json_get_value(json, "type", type, sizeof type))
   278→        return EVT_NONE;
   279→
   280→    if (strcmp(type, "PROPOSAL_CREATE") == 0) return EVT_PROPOSAL_CREATE;
   281→    if (strcmp(type, "VOTE_CAST")       == 0) return EVT_VOTE_CAST;
   282→    if (strcmp(type, "FINALIZE_REQ")    == 0) return EVT_FINALIZE_REQ;
   283→    return EVT_NONE;
   284→}
   285→
   286→static bool parse_event(const char *line, event_t *out_evt)
   287→{
   288→    memset(out_evt, 0, sizeof *out_evt);
   289→    out_evt->type = parse_event_type(line);
   290→    if (out_evt->type == EVT_NONE) {
   291→        return false;
   292→    }
   293→
   294→    char id[64];
   295→    if (!json_get_value(line, "id", id, sizeof id))
   296→        return false;
   297→    strncpy(out_evt->id, id, sizeof out_evt->id - 1);
   298→
   299→    switch (out_evt->type) {
   300→    case EVT_PROPOSAL_CREATE:
   301→        if (!json_get_uint64(line, "voting_deadline", &out_evt->voting_deadline))
   302→            return false;
   303→        break;
   304→    case EVT_VOTE_CAST: {
   305→        char vote[8];
   306→        if (!json_get_value(line, "vote", vote, sizeof vote))
   307→            return false;
   308→        out_evt->vote_yes = (strcmp(vote, "yes") == 0);
   309→        break;
   310→    }
   311→    default: break;
   312→    }
   313→    return true;
   314→}
