   316→/* -------------------------------------------------------------------------- */
   317→/*                             Event Processing                               */
   318→/* -------------------------------------------------------------------------- */
   319→
   320→static void handle_event(const event_t *ev)
   321→{
   322→    governance_proposal_t *p = NULL;
   323→
   324→    switch (ev->type) {
   325→    case EVT_PROPOSAL_CREATE:
   326→        p = proposal_get_or_create(ev->id);
   327→        if (!p) break;
   328→
   329→        p->state           = PROPOSAL_VOTING;
   330→        p->voting_deadline = (time_t)ev->voting_deadline;
   331→        LOGI("Proposal %s entered VOTING state (deadline=%lu)",
   332→             p->id, (unsigned long)p->voting_deadline);
   333→        break;
   334→
   335→    case EVT_VOTE_CAST:
   336→        p = proposal_get_or_create(ev->id);
   337→        if (!p) break;
   338→
   339→        if (p->state != PROPOSAL_VOTING) {
   340→            LOGW("Vote ignored for non-voting proposal %s", p->id);
   341→            break;
   342→        }
   343→
   344→        if (ev->vote_yes)
   345→            p->yes_votes++;
   346→        else
   347→            p->no_votes++;
   348→
   349→        LOGD("Vote registered on %s → yes=%" PRIu64 ", no=%" PRIu64,
   350→             p->id, p->yes_votes, p->no_votes);
   351→        break;
   352→
   353→    case EVT_FINALIZE_REQ:
   354→        pthread_rwlock_rdlock(&g_prop_lock);
   355→        HASH_FIND_STR(g_proposals, ev->id, p);
   356→        pthread_rwlock_unlock(&g_prop_lock);
   357→
   358→        if (!p) {
   359→            LOGW("Finalize requested for unknown proposal %s", ev->id);
   360→            break;
   361→        }
   362→        proposal_try_finalize(p);
   363→        break;
   364→
   365→    default:
   366→        LOGW("Unhandled event type %d", ev->type);
   367→        break;
   368→    }
   369→}
