   371→/* -------------------------------------------------------------------------- */
   372→/*                            Event Consumer Loop                             */
   373→/* -------------------------------------------------------------------------- */
   374→
   375→static atomic_bool g_running = ATOMIC_VAR_INIT(true);
   376→
   377→static void sig_handler(int sig)
   378→{
   379→    (void)sig;
   380→    atomic_store(&g_running, false);
   381→}
   382→
   383→static void *event_consumer_thread(void *arg)
   384→{
   385→    (void)arg;
   386→    LOGI("Event consumer started");
   387→
   388→#ifdef WITH_KAFKA
   389→    /* Kafka setup (omitted for brevity) */
   390→#endif
   391→
   392→    char *line = NULL;
   393→    size_t n   = 0;
   394→
   395→    while (atomic_load(&g_running)) {
   396→        ssize_t rd = getline(&line, &n, stdin);
   397→        if (rd == -1) {
   398→            if (feof(stdin)) {
   399→                LOGI("EOF reached on stdin – terminating");
   400→                break;
   401→            } else if (errno == EINTR) {
   402→                continue;
   403→            } else {
   404→                LOGE("getline failed: %s", strerror(errno));
   405→                break;
   406→            }
   407→        }
   408→        trim(line);
   409→        if (*line == '\0') continue;
   410→
   411→        event_t evt;
   412→        if (!parse_event(line, &evt)) {
   413→            LOGW("Unable to parse event: %s", line);
   414→            continue;
   415→        }
   416→        handle_event(&evt);
   417→    }
   418→
   419→    free(line);
   420→    LOGI("Event consumer stopped");
   421→    return NULL;
   422→}
