   471→    /* -------------------------- Signal handling --------------------------- */
   472→    struct sigaction sa = { .sa_handler = sig_handler };
   473→    sigaction(SIGINT,  &sa, NULL);
   474→    sigaction(SIGTERM, &sa, NULL);
