    66→/* Enumeration of canonical event types emitted onto the bus. */
    67→typedef enum {
    68→    EVT_UNKNOWN = 0,
    69→    EVT_MINT_REQUEST,
    70→    EVT_BID,
    71→    EVT_GOVERNANCE_VOTE,
    72→    EVT_ORACLE_FEED
    73→} event_type_t;
    74→
    75→/* Generic event container. Additional type-specific fields live in
    76→ * sub-structures that mint_engine.c and friends know how to decode. */
    77→typedef struct {
    78→    event_type_t  type;
    79→    char          id[MAX_EVENT_ID_LEN];
    80→    uint64_t      ts_epoch_ms;
    81→    char         *raw_payload;   /* Original JSON string; ownership retained. */
    82→} event_t;
