    87→
    88→typedef struct {
    89→    rd_kafka_t      *rk;          /* Kafka handle */
    90→    rd_kafka_conf_t *conf;        /* Kafka configuration */
    91→    bool             running;
    92→    pthread_t        thread;
    93→} evh_context_t;
    94→
    95→static evh_context_t g_ctx = {0};
