   367→/*
   368→ * iso_timestamp – Convert epoch_ms to ISO-8601 UTC string.
   369→ */
   370→static char *iso_timestamp(uint64_t epoch_ms, char *buf, size_t buf_sz)
   371→{
   372→    time_t sec = (time_t)(epoch_ms / 1000ULL);
   373→    struct tm tm;
   374→    gmtime_r(&sec, &tm);
   375→    size_t n = strftime(buf, buf_sz, "%Y-%m-%dT%H:%M:%S", &tm);
   376→    snprintf(buf + n, buf_sz - n, ".%03" PRIu64 "Z", epoch_ms % 1000ULL);
   377→    return buf;
   378→}
