    76→static pthread_mutex_t log_mtx = PTHREAD_MUTEX_INITIALIZER;
    77→
    78→static void log_time(char *buf, size_t sz)
    79→{
    80→    time_t now = time(NULL);
    81→    struct tm tm;
    82→    gmtime_r(&now, &tm);
    83→    strftime(buf, sz, "%Y-%m-%dT%H:%M:%SZ", &tm);
