    86→#define LOG(level, fmt, ...)                                                       \
    87→    do {                                                                           \
    88→        char _ts[32];                                                              \
    89→        log_time(_ts, sizeof _ts);                                                 \
    90→        pthread_mutex_lock(&log_mtx);                                              \
    91→        fprintf(stderr, "[%s] [%s] [%s] " fmt "\n", _ts, level, SERVICE_NAME,      \
    92→                ##__VA_ARGS__);                                                    \
    93→        pthread_mutex_unlock(&log_mtx);                                            \
    94→    } while (0)
