   131→/* ------------------------------------------------------------------------- */
   132→/*                               Globals & Flags                             */
   133→/* ------------------------------------------------------------------------- */
   134→
   135→static atomic_bool g_shutdown_flag = ATOMIC_VAR_INIT(false);
   136→
   137→/* ------------------------------------------------------------------------- */
   138→/*                           POSIX Queue (bounded)                           */
   139→/* ------------------------------------------------------------------------- */
   140→
   141→typedef struct {
   142→    artifact_t     *buf[MAX_QUEUE_DEPTH];
   143→    size_t          head;
   144→    size_t          tail;
   145→    size_t          count;
   146→    pthread_mutex_t mtx;
   147→    pthread_cond_t  not_empty;
   148→    pthread_cond_t  not_full;
   149→} bqueue_t;
   150→
   151→static void bq_init(bqueue_t *q)
   152→{
   153→    memset(q, 0, sizeof *q);
   154→    pthread_mutex_init(&q->mtx, NULL);
   155→    pthread_cond_init(&q->not_empty, NULL);
   156→    pthread_cond_init(&q->not_full, NULL);
   157→}
   158→
   159→static void bq_push(bqueue_t *q, artifact_t *item)
   160→{
   161→    pthread_mutex_lock(&q->mtx);
   162→    while (q->count == MAX_QUEUE_DEPTH && !atomic_load(&g_shutdown_flag))
   163→        pthread_cond_wait(&q->not_full, &q->mtx);
   164→
   165→    if (atomic_load(&g_shutdown_flag)) { pthread_mutex_unlock(&q->mtx); return; }
   166→
   167→    q->buf[q->tail] = item;
   168→    q->tail = (q->tail + 1) % MAX_QUEUE_DEPTH;
   169→    q->count++;
   170→    pthread_cond_signal(&q->not_empty);
   171→    pthread_mutex_unlock(&q->mtx);
   172→}
   173→
   174→static artifact_t *bq_pop(bqueue_t *q)
   175→{
   176→    pthread_mutex_lock(&q->mtx);
   177→    while (q->count == 0 && !atomic_load(&g_shutdown_flag))
   178→        pthread_cond_wait(&q->not_empty, &q->mtx);
   179→
   180→    artifact_t *item = NULL;
   181→    if (!atomic_load(&g_shutdown_flag) && q->count > 0) {
   182→        item = q->buf[q->head];
   183→        q->head = (q->head + 1) % MAX_QUEUE_DEPTH;
   184→        q->count--;
   185→        pthread_cond_signal(&q->not_full);
   186→    }
   187→    pthread_mutex_unlock(&q->mtx);
   188→    return item;
   189→}
