   247→/* ------------------------------------------------------------------------- */
   248→/*                      Artifact Assembly && Validation                      */
   249→/* ------------------------------------------------------------------------- */
   250→
   251→static int validate_manifest(cJSON *json)
   252→{
   253→    /* Basic sanity checks; deeper schema validation could be added */
   254→    if (!json) return -1;
   255→    /* Example: require mandatory field `artist_address` */
   256→#ifndef HOLO_MINT_FACTORY_STUBS
   257→    cJSON *artist = cJSON_GetObjectItem(json, "artist_address");
   258→    if (!artist || artist->type != cJSON_String) {
   259→        LOG_WARN("Validation failed – missing/invalid artist_address");
   260→        return -1;
   261→    }
   262→#endif
   263→    return 0;
   264→}
