   266→static artifact_t *compose_artifact(const char *payload, size_t len)
   267→{
   268→    (void)len;
   269→    cJSON *json = cJSON_Parse(payload);
   270→    if (!json) {
   271→        LOG_WARN("Invalid JSON in mint request");
   272→        return NULL;
   273→    }
   274→    if (validate_manifest(json) != 0) {
   275→        cJSON_Delete(json);
   276→        return NULL;
   277→    }
   278→
   279→    artifact_t *a = calloc(1, sizeof *a);
   280→    if (!a) {
   281→        LOG_ERROR("Memory allocation failed");
   282→        cJSON_Delete(json);
   283→        return NULL;
   284→    }
   285→
   286→    /* Generate deterministic artifact ID (placeholder: hash of payload) */
   287→    unsigned long hash = 5381;
   288→    for (const char *p = payload; *p; ++p) hash = ((hash << 5) + hash) + *p;
   289→    snprintf(a->id, sizeof a->id, "%lx", hash);
   290→
   291→    a->state       = ARTIFACT_DRAFT;
   292→    a->manifest    = json;
   293→    a->serialized  = cJSON_PrintUnformatted(json);
   294→    if (!a->serialized) {
   295→        LOG_ERROR("Failed to serialize JSON");
   296→        cJSON_Delete(json);
   297→        free(a);
   298→        return NULL;
   299→    }
   300→    LOG_INFO("Composed artifact %s (state=%s)", a->id, state_str(a->state));
   301→    return a;
   302→}
   303→
   304→static void destroy_artifact(artifact_t *a)
   305→{
   306→    if (!a) return;
   307→    cJSON_Delete(a->manifest);
   308→    free(a->serialized);
   309→    free(a);
   310→}
