   315→
   316→typedef struct {
   317→    bqueue_t   *queue;
   318→    config_t   *cfg;
   319→    int         idx;
   320→} worker_arg_t;
   321→
   322→static void *worker_loop(void *arg)
   323→{
   324→    worker_arg_t *wa = arg;
   325→    LOG_INFO("Worker-%d online", wa->idx);
   326→
   327→    while (!atomic_load(&g_shutdown_flag)) {
   328→        artifact_t *a = bq_pop(wa->queue);
   329→        if (!a) continue;
   330→
   331→        /* Simulate on-chain commit latency */
   332→        sleep(1);
   333→
   334→        if (ledger_send_mint_tx(a, wa->cfg) == 0) {
   335→            LOG_INFO("Artifact %s minted successfully", a->id);
   336→        } else {
   337→            LOG_WARN("Ledger commit failed for artifact %s", a->id);
   338→        }
   339→
   340→        destroy_artifact(a);
   341→    }
   342→    LOG_INFO("Worker-%d shutting down", wa->idx);
   343→    return NULL;
   344→}
