   346→/* ------------------------------------------------------------------------- */
   347→/*                             Kafka Consumer Loop                           */
   348→/* ------------------------------------------------------------------------- */
   349→
   350→typedef struct {
   351→    rd_kafka_t *kafka;
   352→    bqueue_t   *queue;
   353→    config_t   *cfg;
   354→} consumer_ctx_t;
   355→
   356→static void *consumer_loop(void *arg)
   357→{
   358→    consumer_ctx_t *ctx = arg;
   359→    LOG_INFO("Kafka consumer thread started (topic=%s)", ctx->cfg->kafka_topic);
   360→
   361→#ifndef HOLO_MINT_FACTORY_STUBS
   362→    rd_kafka_conf_t *conf = rd_kafka_conf_new();
   363→    char errstr[256];
   364→    ctx->kafka = rd_kafka_new(RD_KAFKA_CONSUMER, conf, errstr, sizeof errstr);
   365→    if (!ctx->kafka) {
   366→        LOG_ERROR("Failed to create Kafka consumer: %s", errstr);
   367→        atomic_store(&g_shutdown_flag, true);
   368→        return NULL;
   369→    }
   370→
   371→    rd_kafka_poll_set_consumer(ctx->kafka);
   372→
   373→    rd_kafka_topic_partition_list_t *topics = rd_kafka_topic_partition_list_new(1);
   374→    rd_kafka_topic_partition_list_add(topics, ctx->cfg->kafka_topic, -1);
   375→    if (rd_kafka_subscribe(ctx->kafka, topics) != RD_KAFKA_RESP_ERR_NO_ERROR) {
   376→        LOG_ERROR("Failed to subscribe to topic %s", ctx->cfg->kafka_topic);
   377→        rd_kafka_topic_partition_list_destroy(topics);
   378→        atomic_store(&g_shutdown_flag, true);
   379→        return NULL;
   380→    }
   381→    rd_kafka_topic_partition_list_destroy(topics);
   382→#else
   383→    ctx->kafka = NULL; /* Stub; no real connection */
   384→#endif
   385→
   386→    while (!atomic_load(&g_shutdown_flag)) {
   387→
   388→#ifndef HOLO_MINT_FACTORY_STUBS
   389→        rd_kafka_message_t *msg = rd_kafka_consumer_poll(ctx->kafka, 500);
   390→        if (!msg) { continue; }
   391→        if (msg->err) {
   392→            LOG_WARN("Kafka error: %s", rd_kafka_message_errstr(msg));
   393→            rd_kafka_message_destroy(msg);
   394→            continue;
   395→        }
   396→        /* Process good message */
   397→        artifact_t *a = compose_artifact((char *)msg->payload, msg->len);
   398→        rd_kafka_message_destroy(msg);
   399→#else
