                       errstr, sizeof(errstr));\n    if (!rk)\n        DIE(\"Failed to create Kafka consumer: %s\", errstr);\n\n    rd_kafka_poll_set_consumer(rk);\n\n    rd_kafka_topic_partition_list_t *topics =\n        rd_kafka_topic_partition_list_new(1);\n    rd_kafka_topic_partition_list_add(topics, cfg->topic, -1);\n\n    if (rd_kafka_subscribe(rk, topics))\n        DIE(\"Failed to subscribe to %s\", cfg->topic);\n\n    rd_kafka_topic_partition_list_destroy(topics);\n    LOG(LOG_INFO, \"Kafka consumer ready; brokers=%s, topic=%s\",\n        cfg->kafka_brokers, cfg->topic);\n    return rk;\n}\n\n/* ------------------------------------------------------------------------- */\n/* Event Dispatcher                                                          */\n/* ------------------------------------------------------------------------- */\nstatic int dispatch_event(const muse_cfg_t *cfg,\n                          const char       *event_json,\n                          plugin_t         *cache)\n{\n    /* ---------------------------------\n     * Strategy selection heuristics:\n     *   Input JSON must contain key\n     *     \"strategy\": \"rainbow_shift\"\n     * --------------------------------- */\n    json_error_t jerr;\n    json_t *root = json_loads(event_json, 0, &jerr);\n    if (!root) {\n        LOG(LOG_WARNING, \"Invalid JSON payload: %s\", jerr.text);\n        return -1;\n    }\n\n    const char *strategy = json_string_value(json_object_get(root, \"strategy\"));\n    if (!strategy) {\n        LOG(LOG_INFO, \"No strategy specified; ignoring event\");\n        json_decref(root);\n        return 0;\n    }\n\n    /* Caching: if last loaded plugin matches, reuse it */\n    plugin_t plg  = {0};\n    plugin_t *use = &plg;\n\n    if (cache && strcmp(cache->name, strategy) == 0 && cache->dl_handle) {\n        use = cache;\n    } else {\n        /* unload previous */\n        if (cache && cache->dl_handle)\n            plugin_close(cache);\n\n        /* load new */\n        if (plugin_open(&plg, cfg->plugin_dir, strategy) != 0) {\n            json_decref(root);\n            return -1;\n        }\n    }\n\n    /* Call strategy */\n    char *recipe_json = NULL;\n    int rc = use->run(event_json, &recipe_json);\n    if (rc != 0 || !recipe_json) {\n        LOG(LOG_ERR, \"Strategy `%s` failed (rc=%d)\", strategy, rc);\n        json_decref(root);\n        if (use == &plg) plugin_close(&plg);\n        return -1;\n    }\n\n    /* Send evolution to Mint-Factory */\n    rc = grpc_send_evolution(cfg->grpc_target, recipe_json);\n    free(recipe_json);\n\n    /* Cache plugin for reuse */\n    if (use == &plg && rc == 0 && cache) {\n        *cache = plg; /* shallow copy of handles */\n    } else if (use == &plg) {\n        plugin_close(&plg);\n    }\n\n    json_decref(root);\n    return rc;\n}\n\n/* ------------------------------------------------------------------------- */\n/* Main Event Loop                                                           */\n/* ------------------------------------------------------------------------- */\nstatic int muse_event_loop(const muse_cfg_t *cfg)\n{\n    rd_kafka_t *consumer = kafka_init_consumer(cfg);\n    int exit_code = EXIT_SUCCESS;\n    plugin_t cache = {0}; /* last-used plugin cache */\n\n    while (!g_terminate) {\n        rd_kafka_message_t *rkmsg = rd_kafka_consumer_poll(consumer,\n                                                           POLL_TIMEOUT_MS);\n        if (!rkmsg)\n            continue; /* timeout */\n\n        if (rkmsg->err) {\n            if (rkmsg->err == RD_KAFKA_RESP_ERR__PARTITION_EOF) {\n                /* not a real error */\n            } else {\n                LOG(LOG_ERR, \"Kafka error: %s\", rd_kafka_message_errstr(rkmsg));\n            }\n            rd_kafka_message_destroy(rkmsg);\n            continue;\n        }\n\n        /* The payload is not zero-terminated.  Allocate +1 char. */\n        char *payload = malloc(rkmsg->len + 1);\n        if (!payload) DIE(\"malloc failed\");\n        memcpy(payload, rkmsg->payload, rkmsg->len);\n        payload[rkmsg->len] = '\\0';\n\n        if (dispatch_event(cfg, payload, &cache) != 0) {\n            LOG(LOG_WARNING, \"Event processing failed\");\n            /* keep running */\n        }\n\n        free(payload);\n        rd_kafka_message_destroy(rkmsg);\n    }\n\n    LOG(LOG_INFO, \"Shutting down…\");\n\n    /* Graceful teardown */\n    if (cache.dl_handle)\n        plugin_close(&cache);\n\n    rd_kafka_consumer_close(consumer);\n    rd_kafka_destroy(consumer);\n    rd_kafka_wait_destroyed(2000);\n\n    return exit_code;\n}\n\n/* ------------------------------------------------------------------------- */\n/* Entry Point                                                               */\n/* ------------------------------------------------------------------------- */\nint main(int argc, char **argv)\n{\n    openlog(\"holo-muse\", LOG_PID | LOG_CONS, LOG_DAEMON);\n\n    muse_cfg_t cfg = {\n        .kafka_brokers = dup_or_default(getenv(\"MUSE_KAFKA_BROKERS\"),\n                                        DEFAULT_BROKERS),\n        .topic         = dup_or_default(getenv(\"MUSE_TOPIC\"),      DEFAULT_TOPIC),\n        .plugin_dir    = dup_or_default(getenv(\"MUSE_PLUGIN_DIR\"), DEFAULT_PLUGDIR),\n        .grpc_target   = dup_or_default(getenv(\"MUSE_GRPC_TARGET\"),DEFAULT_GRPC_TGT),\n        .verbosity     = 0\n    };\n\n    muse_parse_cli(argc, argv, &cfg);\n\n    /* Adjust syslog verbosity */\n    setlogmask(LOG_UPTO(cfg.verbosity ? LOG_DEBUG : LOG_INFO));\n\n    LOG(LOG_INFO, \"Muse Observer v%s starting…\", MUSE_VERSION);\n\n    /* Install signals */\n    struct sigaction sa = {\n        .sa_handler = muse_on_signal,\n        .sa_flags   = 0\n    };\n    sigemptyset(&sa.sa_mask);\n    sigaction(SIGINT,  &sa, NULL);\n    sigaction(SIGTERM, &sa, NULL);\n\n    int rc = muse_event_loop(&cfg);\n\n    free(cfg.kafka_brokers);\n    free(cfg.topic);\n    free(cfg.plugin_dir);\n    free(cfg.grpc_target);\n\n    closelog();\n    return rc;\n}\n```", "numLines": 420, "startLine": 1, "totalLines": 420}}

1→/**
     2→ * hc_kafka.h
     3→ *
     4→ * HoloCanvas – Event-Driven Kafka Client Helper
     5→ * --------------------------------------------
     6→ * A minimalist, production-grade wrapper around librdkafka that provides the
     7→ * micro-services within HoloCanvas a uniform, opinionated API for publishing
     8→ * and consuming protobuf / JSON events.  The wrapper adds:
     9→ *
    10→ *  • Sensible default configuration tuned for low-latency micro-services
    11→ *  • Thread-safe producer / consumer handles
    12→ *  • Centralised error handling & structured logging
    13→ *  • Graceful shutdown hooks
    14→ *
    15→ * The file is implemented header-only to avoid the boiler-plate of a separate
    16→ * compilation unit; simply include it wherever Kafka access is required.
    17→ *
    18→ * NOTE: link with -lrdkafka (and -lpthread on most platforms)
    19→ */
    20→#ifndef HC_KAFKA_H
    21→#define HC_KAFKA_H
    22→
    23→/* ────────────────────────────────────────────────────────────────────────── */
    24→/* System headers                                                            */
    25→#include <errno.h>
    26→#include <inttypes.h>
    27→#include <pthread.h>
    28→#include <signal.h>
    29→#include <stdarg.h>
    30→#include <stdbool.h>
    31→#include <stdint.h>
    32→#include <stdio.h>
    33→#include <stdlib.h>
    34→#include <string.h>
    35→#include <time.h>
    36→
    37→/* ────────────────────────────────────────────────────────────────────────── */
    38→/* Third-party headers                                                       */
    39→#include <rdkafka/rdkafka.h> /* librdkafka – https://github.com/confluentinc/librdkafka */
    40→
    41→#ifdef __cplusplus
    42→extern "C" {
    43→#endif
    44→
    45→/* ────────────────────────────────────────────────────────────────────────── */
    46→/* Versioning                                                                */
    47→#define HC_KAFKA_VERSION_MAJOR 1
    48→#define HC_KAFKA_VERSION_MINOR 0
    49→#define HC_KAFKA_VERSION_PATCH 0
    50→
    51→/* ────────────────────────────────────────────────────────────────────────── */
    52→/* Logging                                                                   */
    53→#ifndef HC_KAFKA_LOG_LEVEL
    54→#define HC_KAFKA_LOG_LEVEL LOG_INFO
    55→#endif
    56→
    57→#ifndef HC_KAFKA_LOG_TAG
    58→#define HC_KAFKA_LOG_TAG "hc_kafka"
    59→#endif
    60→
    61→typedef enum
    62→{
    63→    LOG_DEBUG = 0,
    64→    LOG_INFO,
    65→    LOG_WARN,
    66→    LOG_ERROR,
    67→    LOG_FATAL
    68→} hc_log_level_e;
    69→
    70→/* Simple stdio logger; applications may override by defining
    71→ * HC_KAFKA_LOG_FN(level, fmt, ...) prior to including this header. */
    72→#ifndef HC_KAFKA_LOG_FN
    73→#define HC_KAFKA_LOG_FN hc_kafka_default_log
    74→static inline void hc_kafka_default_log(hc_log_level_e level,
    75→                                        const char *file,
    76→                                        int line,
    77→                                        const char *func,
    78→                                        const char *fmt, ...)
    79→{
    80→    if (level < HC_KAFKA_LOG_LEVEL)
    81→        return;
    82→
    83→    static const char *LEVEL_STR[] = {"DEBUG", "INFO", "WARN", "ERROR", "FATAL"};
    84→
    85→    char timebuf[64];
    86→    struct tm tm_now;
    87→    struct timespec ts;
    88→    clock_gettime(CLOCK_REALTIME, &ts);
    89→    localtime_r(&ts.tv_sec, &tm_now);
    90→    strftime(timebuf, sizeof(timebuf), "%Y-%m-%d %H:%M:%S", &tm_now);
    91→
    92→    fprintf((level >= LOG_ERROR) ? stderr : stdout,
    93→            "%s.%03ld [%s] %s:%d %s() : ",
    94→            timebuf,
    95→            ts.tv_nsec / 1000000,
    96→            LEVEL_STR[level],
    97→            file,
    98→            line,
    99→            func);
   100→
   101→    va_list ap;
   102→    va_start(ap, fmt);
   103→    vfprintf((level >= LOG_ERROR) ? stderr : stdout, fmt, ap);
   104→    va_end(ap);
   105→
   106→    fputc('\n', (level >= LOG_ERROR) ? stderr : stdout);
   107→
   108→    if (level == LOG_FATAL)
   109→        abort();
   110→}
   111→#endif /* HC_KAFKA_LOG_FN */
   112→
   113→#define HC_LOG(lvl, ...) HC_KAFKA_LOG_FN((lvl), __FILE__, __LINE__, __func__, __VA_ARGS__)
   114→
   115→/* ────────────────────────────────────────────────────────────────────────── */
   116→/* Error handling                                                            */
   117→
   118→typedef enum
   119→{
   120→    HC_OK = 0,
   121→    HC_ERR = -1,
   122→    HC_ERR_TIMEOUT = -2,
   123→    HC_ERR_EOF = -3
   124→} hc_err_e;
   125→
   126→#define HC_KAFKA_MAX_ERR_STR 512
   127→
   128→static inline const char *hc_strerror(hc_err_e err)
   129→{
   130→    switch (err)
   131→    {
   132→    case HC_OK:
   133→        return "OK";
   134→    case HC_ERR:
   135→        return "Generic error";
   136→    case HC_ERR_TIMEOUT:
   137→        return "Timeout";
   138→    case HC_ERR_EOF:
   139→        return "End of partition";
   140→    default:
   141→        return "Unknown error";
   142→    }
   143→}
