   145→/* ────────────────────────────────────────────────────────────────────────── */
   146→/* Configuration                                                             */
   147→
   148→/* The main configuration object that can be shared across producer/consumer. */
   149→typedef struct
   150→{
   151→    char *bootstrap_servers; /* Comma separated list of brokers */
   152→    char *client_id;         /* Custom client id (optional)     */
   153→} hc_kafka_conf_t;
   154→
   155→/* Forward declarations */
   156→typedef struct hc_kafka_producer_s hc_kafka_producer_t;
   157→typedef struct hc_kafka_consumer_s hc_kafka_consumer_t;
   158→
   159→/* ────────────────────────────────────────────────────────────────────────── */
   160→/* Global state                                                              */
   161→
   162→static pthread_once_t g_kafka_global_init_once = PTHREAD_ONCE_INIT;
   163→
   164→/* Called once per process */
   165→static void hc_kafka__rdk_init_once(void)
   166→{
   167→    rd_kafka_configure_events(); /* noop stub if disabled in librdkafka build */
   168→    /* Nothing else for now */
   169→}
   170→
   171→/* Ensure global initialization of librdkafka – must be called before any API. */
   172→static inline void hc_kafka_global_init(void)
   173→{
   174→    (void)pthread_once(&g_kafka_global_init_once, hc_kafka__rdk_init_once);
   175→}
   176→
   177→/* ────────────────────────────────────────────────────────────────────────── */
   178→/* Producer                                                                  */
   179→
   180→struct hc_kafka_producer_s
   181→{
   182→    rd_kafka_t *rk;
   183→    rd_kafka_conf_t *conf;
   184→    char errstr[HC_KAFKA_MAX_ERR_STR];
   185→    pthread_mutex_t lock;
   186→};
   187→
   188→static inline hc_kafka_producer_t *
   189→hc_kafka_producer_new(const hc_kafka_conf_t *cfg)
   190→{
   191→    hc_kafka_global_init();
   192→
   193→    hc_kafka_producer_t *self = calloc(1, sizeof(*self));
   194→    if (!self)
   195→    {
   196→        HC_LOG(LOG_FATAL, "Out of memory creating producer");
   197→        return NULL;
   198→    }
   199→
   200→    self->conf = rd_kafka_conf_new();
   201→    rd_kafka_conf_set_log_cb(self->conf, NULL); /* Use default internal logging */
   202→
   203→    if (rd_kafka_conf_set(self->conf, "bootstrap.servers", cfg->bootstrap_servers,
   204→                          self->errstr, sizeof(self->errstr)) != RD_KAFKA_CONF_OK)
   205→    {
   206→        HC_LOG(LOG_ERROR, "Kafka conf error: %s", self->errstr);
   207→        goto fail;
   208→    }
   209→
   210→    if (cfg->client_id &&
   211→        rd_kafka_conf_set(self->conf, "client.id", cfg->client_id,
   212→                          self->errstr, sizeof(self->errstr)) != RD_KAFKA_CONF_OK)
   213→    {
   214→        HC_LOG(LOG_WARN, "Kafka conf client.id: %s", self->errstr);
   215→    }
   216→
   217→    /* Improve latency for micro-services */
   218→    rd_kafka_conf_set(self->conf, "queue.buffering.max.ms", "5", NULL, 0);
   219→    rd_kafka_conf_set(self->conf, "linger.ms", "0", NULL, 0);
   220→    rd_kafka_conf_set(self->conf, "acks", "all", NULL, 0);
   221→
   222→    self->rk = rd_kafka_new(RD_KAFKA_PRODUCER, self->conf,
   223→                            self->errstr, sizeof(self->errstr));
   224→    if (!self->rk)
   225→    {
   226→        HC_LOG(LOG_ERROR, "Kafka producer init: %s", self->errstr);
   227→        goto fail;
   228→    }
   229→
   230→    pthread_mutex_init(&self->lock, NULL);
   231→    HC_LOG(LOG_INFO, "Kafka producer created (client.id=%s)",
   232→           cfg->client_id ? cfg->client_id : "N/A");
   233→    return self;
   234→
   235→fail:
   236→    if (self->conf)
   237→        rd_kafka_conf_destroy(self->conf);
   238→    free(self);
   239→    return NULL;
   240→}
