   242→/*
   243→ * Non-blocking send – copies payload, returns immediately.
   244→ * On success returns HC_OK.  In case of queue‐full backpressure, waits
   245→ * (block_ms) milliseconds before giving up with HC_ERR_TIMEOUT.
   246→ */
   247→static inline hc_err_e
   248→hc_kafka_producer_send(hc_kafka_producer_t *self,
   249→                       const char *topic,
   250→                       const void *payload,
   251→                       size_t len,
   252→                       int32_t partition, /* RD_KAFKA_PARTITION_UA for any */
   253→                       int block_ms)
   254→{
   255→    if (!self || !topic)
   256→        return HC_ERR;
   257→
   258→    rd_kafka_resp_err_t err;
   259→    int remaining_wait = block_ms;
   260→
   261→    pthread_mutex_lock(&self->lock);
   262→
   263→retry:
   264→    err = rd_kafka_producev(
   265→        self->rk,
   266→        RD_KAFKA_V_TOPIC(topic),
   267→        RD_KAFKA_V_PARTITION(partition),
   268→        RD_KAFKA_V_MSGFLAGS(RD_KAFKA_MSG_F_COPY),
   269→        RD_KAFKA_V_VALUE(payload, len),
   270→        RD_KAFKA_V_END);
   271→
   272→    if (!err)
   273→    {
   274→        pthread_mutex_unlock(&self->lock);
   275→        return HC_OK; /* queued successfully */
   276→    }
   277→
   278→    if (err == RD_KAFKA_RESP_ERR__QUEUE_FULL && remaining_wait > 0)
   279→    {
   280→        rd_kafka_poll(self->rk, 0);  /* serve delivery reports */
   281→        const int backoff = 50;      /* ms */
   282→        struct timespec ts = {.tv_sec = 0, .tv_nsec = backoff * 1000000};
   283→        nanosleep(&ts, NULL);
   284→        remaining_wait -= backoff;
   285→        goto retry;
   286→    }
   287→
   288→    HC_LOG(LOG_ERROR, "Produce failed: %s", rd_kafka_err2str(err));
   289→    pthread_mutex_unlock(&self->lock);
   290→    return HC_ERR;
   291→}
   292→
   293→/* Poll delivery callbacks.  Return number of events served. */
   294→static inline int
   295→hc_kafka_producer_poll(hc_kafka_producer_t *self, int timeout_ms)
   296→{
   297→    return rd_kafka_poll(self->rk, timeout_ms);
   298→}
   299→
   300→/* Flush outstanding messages; timeout_ms < 0 waits indefinitely. */
   301→static inline hc_err_e
   302→hc_kafka_producer_flush(hc_kafka_producer_t *self, int timeout_ms)
   303→{
   304→    int ret = rd_kafka_flush(self->rk, timeout_ms < 0 ? INT_MAX : timeout_ms);
   305→    return (ret == RD_KAFKA_RESP_ERR_NO_ERROR) ? HC_OK : HC_ERR_TIMEOUT;
   306→}
   307→
   308→static inline void
   309→hc_kafka_producer_destroy(hc_kafka_producer_t *self)
   310→{
   311→    if (!self)
   312→        return;
   313→
   314→    hc_kafka_producer_flush(self, 10 * 1000);
   315→    rd_kafka_destroy(self->rk);
   316→    pthread_mutex_destroy(&self->lock);
   317→    free(self);
   318→}
   319→
   320→/* ────────────────────────────────────────────────────────────────────────── */
   321→/* Consumer                                                                  */
   322→
   323→typedef void (*hc_kafka_msg_cb)(const rd_kafka_message_t *rkmsg, void *opaque);
   324→
   325→struct hc_kafka_consumer_s
   326→{
   327→    rd_kafka_t *rk;
   328→    rd_kafka_conf_t *conf;
   329→    rd_kafka_topic_partition_list_t *subscribed;
   330→    hc_kafka_msg_cb on_msg;
   331→    void *opaque;
   332→    char errstr[HC_KAFKA_MAX_ERR_STR];
   333→};
   334→
   335→static inline hc_kafka_consumer_t *
   336→hc_kafka_consumer_new(const hc_kafka_conf_t *cfg,
   337→                      const char *group_id,
   338→                      hc_kafka_msg_cb on_msg,
   339→                      void *opaque)
   340→{
   341→    hc_kafka_global_init();
   342→
   343→    hc_kafka_consumer_t *self = calloc(1, sizeof(*self));
   344→    if (!self)
   345→        return NULL;
   346→
   347→    self->conf = rd_kafka_conf_new();
   348→    rd_kafka_conf_set(self->conf, "bootstrap.servers", cfg->bootstrap_servers, NULL, 0);
   349→    rd_kafka_conf_set(self->conf, "group.id", group_id, NULL, 0);
   350→    rd_kafka_conf_set(self->conf, "auto.offset.reset", "earliest", NULL, 0);
   351→    rd_kafka_conf_set(self->conf, "enable.auto.commit", "false", NULL, 0);
   352→    rd_kafka_conf_set(self->conf, "enable.partition.eof", "true", NULL, 0);
   353→
   354→    if (cfg->client_id)
   355→        rd_kafka_conf_set(self->conf, "client.id", cfg->client_id, NULL, 0);
   356→
   357→    self->rk = rd_kafka_new(RD_KAFKA_CONSUMER, self->conf,
   358→                            self->errstr, sizeof(self->errstr));
   359→    if (!self->rk)
   360→    {
   361→        HC_LOG(LOG_ERROR, "Kafka consumer new: %s", self->errstr);
   362→        goto fail;
   363→    }
   364→
   365→    rd_kafka_poll_set_consumer(self->rk); /* Redirect rd_kafka_poll() to consumer_poll */
   366→
   367→    self->on_msg = on_msg;
   368→    self->opaque = opaque;
   369→
   370→    HC_LOG(LOG_INFO, "Kafka consumer created (group=%s)", group_id);
   371→    return self;
   372→
   373→fail:
   374→    if (self->conf)
   375→        rd_kafka_conf_destroy(self->conf);
   376→    free(self);
   377→    return NULL;
   378→}
   379→
   380→static inline hc_err_e
   381→hc_kafka_consumer_subscribe(hc_kafka_consumer_t *self,
   382→                            const char *const *topics,
   383→                            size_t topic_cnt)
   384→{
   385→    if (!self || topic_cnt == 0)
   386→        return HC_ERR;
   387→
   388→    self->subscribed = rd_kafka_topic_partition_list_new((int)topic_cnt);
   389→    for (size_t i = 0; i < topic_cnt; ++i)
   390→        rd_kafka_topic_partition_list_add(self->subscribed, topics[i], RD_KAFKA_PARTITION_UA);
   391→
   392→    rd_kafka_resp_err_t err = rd_kafka_subscribe(self->rk, self->subscribed);
   393→    if (err)
   394→    {
   395→        HC_LOG(LOG_ERROR, "Failed to subscribe: %s", rd_kafka_err2str(err));
   396→        rd_kafka_topic_partition_list_destroy(self->subscribed);
   397→        self->subscribed = NULL;
   398→        return HC_ERR;
   399→    }
   400→    return HC_OK;
   401→}
   402→
   403→/* Blocking poll loop helper; returns HC_ERR on fatal error or when stop flag set */
   404→static inline hc_err_e
   405→hc_kafka_consumer_poll_loop(hc_kafka_consumer_t *self,
   406→                            int timeout_ms,
   407→                            volatile sig_atomic_t *stop_flag)
   408→{
   409→    while (!(*stop_flag))
   410→    {
   411→        rd_kafka_message_t *rkmsg = rd_kafka_consumer_poll(self->rk, timeout_ms);
   412→        if (!rkmsg)
   413→            continue;
   414→
   415→        if (rkmsg->err)
   416→        {
   417→            if (rkmsg->err == RD_KAFKA_RESP_ERR__PARTITION_EOF)
   418→            {
   419→                /* Silently ignore EOFs to avoid log spam */
   420→                rd_kafka_message_destroy(rkmsg);
   421→                continue;
   422→            }
   423→            HC_LOG(LOG_WARN, "Consumer error: %s", rd_kafka_message_errstr(rkmsg));
   424→            rd_kafka_message_destroy(rkmsg);
   425→            continue;
   426→        }
   427→
   428→        /* Dispatch to user callback */
   429→        if (self->on_msg)
   430→            self->on_msg(rkmsg, self->opaque);
   431→
   432→        rd_kafka_message_destroy(rkmsg);
   433→    }
   434→
   435→    return HC_OK;
   436→}
   437→
   438→static inline hc_err_e
   439→hc_kafka_consumer_commit(hc_kafka_consumer_t *self)
   440→{
   441→    rd_kafka_resp_err_t err = rd_kafka_commit(self->rk, NULL, false);
   442→    if (err)
   443→    {
   444→        HC_LOG(LOG_ERROR, "Commit failed: %s", rd_kafka_err2str(err));
   445→        return HC_ERR;
   446→    }
   447→    return HC_OK;
   448→}
   449→
   450→static inline void
   451→hc_kafka_consumer_destroy(hc_kafka_consumer_t *self)
   452→{
   453→    if (!self)
   454→        return;
   455→
   456→    rd_kafka_consumer_close(self->rk);
   457→    rd_kafka_topic_partition_list_destroy(self->subscribed);
   458→    rd_kafka_destroy(self->rk);
   459→    free(self);
   460→}
   461→
   462→/* ────────────────────────────────────────────────────────────────────────── */
   463→/* Utilities                                                                 */
   464→
   465→/* Convert timeval to milliseconds since epoch */
   466→static inline int64_t hc_now_ms(void)
   467→{
   468→    struct timespec ts;
   469→    clock_gettime(CLOCK_REALTIME, &ts);
   470→    return (int64_t)ts.tv_sec * 1000 + ts.tv_nsec / 1000000;
   471→}
