   174→static void dr_msg_cb(rd_kafka_t *rk,
   175→                      const rd_kafka_message_t *m,
   176→                      void *opaque)
   177→{
   178→    hc_kafka_client_t *cli = (hc_kafka_client_t *)opaque;
   179→    hc_kafka_delivery_t d  = {
