   286→int hc_kafka_client_subscribe(hc_kafka_client_t *cli,
   287→                              const char *const *topics,
   288→                              size_t topic_count)
   289→{
   290→    if (!cli || !topics || topic_count == 0)
   291→        return -EINVAL;
   292→
   293→    rd_kafka_conf_t *c_conf = rd_kafka_conf_dup(cli->conf);
   294→    rd_kafka_conf_set(c_conf, "enable.auto.commit", "false", NULL, 0);
   295→
   296→    char errstr[512];
   297→    rd_kafka_t *c_consumer = rd_kafka_new(RD_KAFKA_CONSUMER, c_conf,
   298→                                          errstr, sizeof(errstr));
   299→    if (!c_consumer) {
   300→        hc_kafka_log(HC_KAFKA_LOG_ERROR,
   301→                     "Failed to create consumer: %s", errstr);
   302→        rd_kafka_conf_destroy(c_conf);
   303→        return -1;
   304→    }
   305→
   306→    rd_kafka_poll_set_consumer(c_consumer);
   307→
   308→    cli->subscribed = rd_kafka_topic_partition_list_new((int)topic_count);
   309→    for (size_t i = 0; i < topic_count; ++i)
   310→        rd_kafka_topic_partition_list_add(cli->subscribed, topics[i],
   311→                                          RD_KAFKA_PARTITION_UA);
   312→
   313→    rd_kafka_resp_err_t err =
   314→        rd_kafka_subscribe(c_consumer, cli->subscribed);
   315→    if (err) {
   316→        hc_kafka_log(HC_KAFKA_LOG_ERROR,
   317→                     "Subscription failed: %s",
   318→                     rd_kafka_err2str(err));
   319→        rd_kafka_destroy(c_consumer);
   320→        return -1;
   321→    }
   322→
   323→    /* Swap the consumer instance into the existing handle */
   324→    cli->rk = c_consumer;
   325→    hc_kafka_log(HC_KAFKA_LOG_INFO,
   326→                 "Subscribed to %zu topic(s)", topic_count);
   327→
   328→    return 0;
   329→}
