   331→int hc_kafka_client_poll(hc_kafka_client_t *cli,
   332→                         int timeout_ms,
   333→                         hc_kafka_msg_cb on_msg,
   334→                         void *opaque)
   335→{
   336→    if (!cli || !on_msg || timeout_ms < 0)
   337→        return -EINVAL;
   338→
   339→    rd_kafka_message_t *msg =
   340→        rd_kafka_consumer_poll(cli->rk, timeout_ms);
   341→    if (!msg) return 0; /* Timed out */
   342→
   343→    if (msg->err) {
   344→        if (msg->err == RD_KAFKA_RESP_ERR__PARTITION_EOF) {
   345→            hc_kafka_log(HC_KAFKA_LOG_DEBUG,
   346→                         "Reached end of %s [%d] @ %" PRId64,
   347→                         rd_kafka_topic_name(msg->rkt),
   348→                         msg->partition, msg->offset);
   349→        } else {
   350→            hc_kafka_log(HC_KAFKA_LOG_ERROR,
   351→                         "Consume error: %s",
   352→                         rd_kafka_message_errstr(msg));
   353→        }
   354→        rd_kafka_message_destroy(msg);
   355→        return -1;
   356→    }
   357→
   358→    on_msg(msg, opaque);
   359→    rd_kafka_message_destroy(msg);
   360→
   361→    return 1;
   362→}
