/**
 * hc_event_dispatcher.c
 *
 * HoloCanvas – Shared Event Dispatcher Implementation
 * ----------------------------------------------------
 * Implementation of the generic event dispatcher that centralizes Kafka
 * event consumption and dispatching logic across HoloCanvas services.
 *
 * Key features:
 *   - Hash map-based handler registry for O(1) event type lookup
 *   - Thread-safe operation with atomic flags for shutdown
 *   - Configurable Kafka consumer settings
 *   - JSON event parsing with type-based routing
 *
 * Copyright (c) 2024 The HoloCanvas Contributors
 * SPDX-License-Identifier: Apache-2.0
 */

#include "hc_event_dispatcher.h"

#include <errno.h>
#include <pthread.h>
#include <signal.h>
#include <stdatomic.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>

#include <jansson.h>
#include <librdkafka/rdkafka.h>

/* ============================================================================
 * Internal Constants
 * ============================================================================ */

#define DISPATCHER_LOG_PREFIX "[EventDispatcher] "
#define DEFAULT_POLL_TIMEOUT_MS 500
#define HANDLER_HASH_SIZE 64  /* Number of hash buckets */
#define MAX_EVENT_TYPE_LEN 128

/* ============================================================================
 * Internal Logging
 * ============================================================================ */

typedef enum {
    DISP_LOG_DEBUG = 0,
    DISP_LOG_INFO,
    DISP_LOG_WARN,
    DISP_LOG_ERROR
} disp_log_level_t;

static void disp_log(disp_log_level_t level, const char *fmt, ...) {
    static const char *LEVEL_STR[] = {"DEBUG", "INFO", "WARN", "ERROR"};

    char timebuf[32];
    struct timespec ts;
    clock_gettime(CLOCK_REALTIME, &ts);
    struct tm tm;
    localtime_r(&ts.tv_sec, &tm);
    strftime(timebuf, sizeof(timebuf), "%Y-%m-%d %H:%M:%S", &tm);

    FILE *out = (level >= DISP_LOG_ERROR) ? stderr : stdout;

    fprintf(out, "%s.%03ld %s%s: ", timebuf, ts.tv_nsec / 1000000,
            DISPATCHER_LOG_PREFIX, LEVEL_STR[level]);

    va_list ap;
    va_start(ap, fmt);
    vfprintf(out, fmt, ap);
    va_end(ap);

    fputc('\n', out);
}

#define LOG_DEBUG(...) disp_log(DISP_LOG_DEBUG, __VA_ARGS__)
#define LOG_INFO(...)  disp_log(DISP_LOG_INFO, __VA_ARGS__)
#define LOG_WARN(...)  disp_log(DISP_LOG_WARN, __VA_ARGS__)
#define LOG_ERROR(...) disp_log(DISP_LOG_ERROR, __VA_ARGS__)

/* ============================================================================
 * Internal Data Structures
 * ============================================================================ */

/**
 * Entry in the handler linked list for a single hash bucket.
 */
typedef struct HandlerEntry {
    char *event_type;               /**< Event type key (owned) */
    event_handler_func_t handler;   /**< Handler function pointer */
    struct HandlerEntry *next;      /**< Next entry in bucket chain */
} HandlerEntry;

/**
 * Hash map bucket for handler registry.
 */
typedef struct {
    HandlerEntry *head;             /**< Head of handler chain */
} HandlerBucket;

/**
 * Handler registry using a simple hash map.
 */
typedef struct {
    HandlerBucket buckets[HANDLER_HASH_SIZE];
    pthread_rwlock_t lock;          /**< Read-write lock for thread safety */
    size_t count;                   /**< Total number of registered handlers */
} HandlerRegistry;

/**
 * Internal dispatcher state.
 */
struct EventDispatcher {
    /* Kafka resources */
    rd_kafka_t *consumer;
    rd_kafka_conf_t *kafka_conf;
    rd_kafka_topic_partition_list_t *subscribed_topics;

    /* Configuration */
    char *brokers;
    char *topic;
    char *group_id;
    int poll_timeout_ms;

    /* Handler registry */
    HandlerRegistry registry;

    /* User context */
    void *user_context;

    /* Runtime state */
    atomic_bool running;
    atomic_bool should_stop;
};

/* Global dispatcher pointer for signal handler */
static EventDispatcher *g_signal_dispatcher = NULL;

/* ============================================================================
 * Hash Map Implementation
 * ============================================================================ */

/**
 * Simple DJB2 hash function for strings.
 */
static unsigned int hash_string(const char *str) {
    unsigned int hash = 5381;
    int c;
    while ((c = *str++)) {
        hash = ((hash << 5) + hash) + (unsigned int)c;
    }
    return hash;
}

static void registry_init(HandlerRegistry *reg) {
    memset(reg->buckets, 0, sizeof(reg->buckets));
    pthread_rwlock_init(&reg->lock, NULL);
    reg->count = 0;
}

static void registry_destroy(HandlerRegistry *reg) {
    pthread_rwlock_wrlock(&reg->lock);

    for (int i = 0; i < HANDLER_HASH_SIZE; i++) {
        HandlerEntry *entry = reg->buckets[i].head;
        while (entry) {
            HandlerEntry *next = entry->next;
            free(entry->event_type);
            free(entry);
            entry = next;
        }
        reg->buckets[i].head = NULL;
    }
    reg->count = 0;

    pthread_rwlock_unlock(&reg->lock);
    pthread_rwlock_destroy(&reg->lock);
}

static hc_error_t registry_add(HandlerRegistry *reg,
                               const char *event_type,
                               event_handler_func_t handler) {
    if (!event_type || !handler) {
        return HC_ERROR_PACK(HC_SUBSYS_COMMON, HC_SEV_ERROR, HC_EC_INVALID_ARGUMENT);
    }

    unsigned int idx = hash_string(event_type) % HANDLER_HASH_SIZE;

    HandlerEntry *entry = malloc(sizeof(HandlerEntry));
    if (!entry) {
        return HC_ERROR_PACK(HC_SUBSYS_COMMON, HC_SEV_ERROR, HC_EC_OUT_OF_MEMORY);
    }

    entry->event_type = strdup(event_type);
    if (!entry->event_type) {
        free(entry);
        return HC_ERROR_PACK(HC_SUBSYS_COMMON, HC_SEV_ERROR, HC_EC_OUT_OF_MEMORY);
    }
    entry->handler = handler;

    pthread_rwlock_wrlock(&reg->lock);

    /* Prepend to bucket chain */
    entry->next = reg->buckets[idx].head;
    reg->buckets[idx].head = entry;
    reg->count++;

    pthread_rwlock_unlock(&reg->lock);

    return HC_OK;
}

/**
 * Find and invoke all handlers for a given event type.
 * Returns the number of handlers invoked.
 */
static int registry_dispatch(HandlerRegistry *reg,
                             const char *event_type,
                             const char *payload,
                             size_t payload_len,
                             void *user_context) {
    unsigned int idx = hash_string(event_type) % HANDLER_HASH_SIZE;
    int count = 0;

    pthread_rwlock_rdlock(&reg->lock);

    HandlerEntry *entry = reg->buckets[idx].head;
    while (entry) {
        if (strcmp(entry->event_type, event_type) == 0) {
            hc_error_t rc = entry->handler(event_type, payload, payload_len, user_context);
            if (rc != HC_OK) {
                LOG_WARN("Handler for '%s' returned error: %s",
                         event_type, hc_error_str(rc));
            }
            count++;
        }
        entry = entry->next;
    }

    pthread_rwlock_unlock(&reg->lock);

    return count;
}

/* ============================================================================
 * Kafka Callbacks
 * ============================================================================ */

static void kafka_log_cb(const rd_kafka_t *rk, int level,
                         const char *fac, const char *buf) {
    (void)rk;
    (void)fac;
    if (level <= 3) {
        LOG_ERROR("rdkafka: %s", buf);
    } else if (level <= 5) {
        LOG_WARN("rdkafka: %s", buf);
    } else {
        LOG_DEBUG("rdkafka: %s", buf);
    }
}

static void kafka_error_cb(rd_kafka_t *rk, int err,
                           const char *reason, void *opaque) {
    (void)rk;
    (void)opaque;
    LOG_ERROR("Kafka error (%d): %s", err, reason);
}

/* ============================================================================
 * Event Processing
 * ============================================================================ */

/**
 * Parse JSON message and extract event type and payload.
 * Expected format: { "type": "EVENT_TYPE", "payload": {...} }
 */
static hc_error_t process_message(EventDispatcher *disp,
                                  const void *data,
                                  size_t len) {
    json_error_t jerr;
    json_t *root = json_loadb((const char *)data, len, 0, &jerr);
    if (!root) {
        LOG_WARN("JSON parse error at line %d: %s", jerr.line, jerr.text);
        return HC_ERROR_PACK(HC_SUBSYS_COMMON, HC_SEV_WARNING, HC_EC_DATA_CORRUPT);
    }

    /* Extract event type */
    json_t *type_node = json_object_get(root, "type");
    if (!json_is_string(type_node)) {
        LOG_WARN("Event missing 'type' field or not a string");
        json_decref(root);
        return HC_ERROR_PACK(HC_SUBSYS_COMMON, HC_SEV_WARNING, HC_EC_DATA_CORRUPT);
    }

    const char *event_type = json_string_value(type_node);

    /* Extract payload - pass the entire payload subtree as JSON string */
    json_t *payload_node = json_object_get(root, "payload");
    char *payload_str = NULL;
    size_t payload_len = 0;

    if (payload_node) {
        payload_str = json_dumps(payload_node, JSON_COMPACT);
        if (payload_str) {
            payload_len = strlen(payload_str);
        }
    }

    /* If no payload, use the raw message */
    if (!payload_str) {
        payload_str = strndup((const char *)data, len);
        payload_len = len;
    }

    LOG_DEBUG("Processing event: type=%s, payload_len=%zu", event_type, payload_len);

    /* Dispatch to registered handlers */
    int handler_count = registry_dispatch(&disp->registry,
                                          event_type,
                                          payload_str,
                                          payload_len,
                                          disp->user_context);

    if (handler_count == 0) {
        LOG_DEBUG("No handlers registered for event type '%s'", event_type);
    } else {
        LOG_DEBUG("Dispatched '%s' to %d handler(s)", event_type, handler_count);
    }

    free(payload_str);
    json_decref(root);

    return HC_OK;
}

/* ============================================================================
 * Signal Handling
 * ============================================================================ */

