 * Kafka Callbacks
 * ============================================================================ */

static void kafka_log_cb(const rd_kafka_t *rk, int level,
                         const char *fac, const char *buf) {
    (void)rk;
    (void)fac;
    if (level <= 3) {
        LOG_ERROR("rdkafka: %s", buf);
