            payload_len = strlen(payload_str);
        }
    }

    /* If no payload, use the raw message */
    if (!payload_str) {
        payload_str = strndup((const char *)data, len);
        payload_len = len;
    }

    LOG_DEBUG("Processing event: type=%s, payload_len=%zu", event_type, payload_len);

    /* Dispatch to registered handlers */
    int handler_count = registry_dispatch(&disp->registry,
                                          event_type,
                                          payload_str,
                                          payload_len,
                                          disp->user_context);

    if (handler_count == 0) {
        LOG_DEBUG("No handlers registered for event type '%s'", event_type);
    } else {
        LOG_DEBUG("Dispatched '%s' to %d handler(s)", event_type, handler_count);
    }

    free(payload_str);
