#define DISPATCHER_LOG_PREFIX "[EventDispatcher] "
#define DEFAULT_POLL_TIMEOUT_MS 500
#define HANDLER_HASH_SIZE 64  /* Number of hash buckets */
#define MAX_EVENT_TYPE_LEN 128

/* ============================================================================
