typedef enum {
    DISP_LOG_DEBUG = 0,
    DISP_LOG_INFO,
    DISP_LOG_WARN,
    DISP_LOG_ERROR
} disp_log_level_t;

static void disp_log(disp_log_level_t level, const char *fmt, ...) {
    static const char *LEVEL_STR[] = {"DEBUG", "INFO", "WARN", "ERROR"};

    char timebuf[32];
    struct timespec ts;
    clock_gettime(CLOCK_REALTIME, &ts);
