/*
 * HoloCanvas Governance Hall – Main Service Entrypoint (Refactored)
 *
 * Project      : HoloCanvas – A Micro-Gallery Blockchain for Generative Artifacts
 * Service      : governance_hall
 * File         : src/main.c
 * Description  :
 *      Governance-Hall is the DAO brain of HoloCanvas. This refactored version
 *      uses the shared EventDispatcher module for Kafka event consumption,
 *      eliminating duplicated boilerplate code.
 *
 *      The service now:
 *          • Uses event_dispatcher_create() to set up Kafka connection
 *          • Registers specific event handlers for governance events
 *          • Delegates event loop to event_dispatcher_run()
 */

#define _POSIX_C_SOURCE 200809L

#include <errno.h>
#include <signal.h>
#include <stdatomic.h>
#include <stdbool.h>
#include <stdint.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <pthread.h>
#include <unistd.h>

#include "uthash.h"

/* Include the shared event dispatcher */
#include "shared/event_dispatcher/hc_event_dispatcher.h"

/* -------------------------------------------------------------------------- */
/*                               Build-time Info                              */
/* -------------------------------------------------------------------------- */
#define GOV_HALL_VERSION "1.3.0"
#define BUILD_TIMESTAMP  __DATE__ " " __TIME__

/* -------------------------------------------------------------------------- */
/*                                 Logging                                    */
/* -------------------------------------------------------------------------- */
typedef enum {
    LOG_DEBUG,
    LOG_INFO,
    LOG_WARN,
    LOG_ERROR,
    LOG_FATAL
} log_level_t;

static log_level_t g_log_level = LOG_INFO;

static const char *log_level_str(log_level_t lvl)
{
    switch (lvl) {
    case LOG_DEBUG: return "DEBUG";
    case LOG_INFO:  return "INFO ";
    case LOG_WARN:  return "WARN ";
    case LOG_ERROR: return "ERROR";
    case LOG_FATAL: return "FATAL";
    default:        return "?????";
    }
}

static void log_internal(log_level_t lvl,
                         const char *file,
                         int line,
                         const char *fmt, ...)
{
    if (lvl < g_log_level) {
        return;
    }

    struct timespec ts;
    clock_gettime(CLOCK_REALTIME, &ts);

    struct tm tm;
    localtime_r(&ts.tv_sec, &tm);

    char ts_buf[64];
    strftime(ts_buf, sizeof ts_buf, "%Y-%m-%d %H:%M:%S", &tm);

    fprintf((lvl >= LOG_ERROR) ? stderr : stdout,
            "%s.%03ld [%s] %s:%d: ",
            ts_buf, ts.tv_nsec / 1000000,
            log_level_str(lvl),
            file, line);

    va_list ap;
    va_start(ap, fmt);
    vfprintf((lvl >= LOG_ERROR) ? stderr : stdout, fmt, ap);
    va_end(ap);

    fputc('\n', (lvl >= LOG_ERROR) ? stderr : stdout);

    if (lvl == LOG_FATAL) {
        abort();
    }
}

#define LOGD(...) log_internal(LOG_DEBUG, __FILE__, __LINE__, __VA_ARGS__)
#define LOGI(...) log_internal(LOG_INFO,  __FILE__, __LINE__, __VA_ARGS__)
#define LOGW(...) log_internal(LOG_WARN,  __FILE__, __LINE__, __VA_ARGS__)
#define LOGE(...) log_internal(LOG_ERROR, __FILE__, __LINE__, __VA_ARGS__)
#define LOGF(...) log_internal(LOG_FATAL, __FILE__, __LINE__, __VA_ARGS__)

/* -------------------------------------------------------------------------- */
/*                         Governance Proposal State                          */
/* -------------------------------------------------------------------------- */

typedef enum {
    PROPOSAL_DRAFT = 0,
    PROPOSAL_VOTING,
    PROPOSAL_ACCEPTED,
    PROPOSAL_REJECTED,
    PROPOSAL_EXECUTED
} proposal_state_t;

typedef struct governance_proposal {
    char id[64];
    proposal_state_t state;
    uint64_t yes_votes;
    uint64_t no_votes;
    time_t created_at;
    time_t voting_deadline;
    UT_hash_handle hh;
} governance_proposal_t;

/* In-memory key-value store of proposals */
static governance_proposal_t *g_proposals = NULL;
static pthread_rwlock_t g_prop_lock = PTHREAD_RWLOCK_INITIALIZER;

/* Lookup or create a proposal record */
static governance_proposal_t *
proposal_get_or_create(const char *id)
{
    governance_proposal_t *p = NULL;
    pthread_rwlock_rdlock(&g_prop_lock);
    HASH_FIND_STR(g_proposals, id, p);
    pthread_rwlock_unlock(&g_prop_lock);

    if (p) {
        return p;
    }

    pthread_rwlock_wrlock(&g_prop_lock);
    HASH_FIND_STR(g_proposals, id, p);
    if (!p) {
        p = calloc(1, sizeof *p);
        if (!p) {
            pthread_rwlock_unlock(&g_prop_lock);
            LOGE("Memory allocation failed for proposal '%s'", id);
            return NULL;
        }
        strncpy(p->id, id, sizeof p->id - 1);
        p->created_at = time(NULL);
        p->state      = PROPOSAL_DRAFT;
        HASH_ADD_STR(g_proposals, id, p);
        LOGI("Created new proposal %s", id);
    }
    pthread_rwlock_unlock(&g_prop_lock);
    return p;
}

static void proposal_try_finalize(governance_proposal_t *p)
{
    if (p->state != PROPOSAL_VOTING) {
        return;
    }

    time_t now = time(NULL);
    if (now < p->voting_deadline) {
        return;
    }

    p->state = (p->yes_votes > p->no_votes)
                 ? PROPOSAL_ACCEPTED
                 : PROPOSAL_REJECTED;

    LOGI("Proposal %s finalized as %s (yes=%" PRIu64 ", no=%" PRIu64 ")",
         p->id,
         (p->state == PROPOSAL_ACCEPTED) ? "ACCEPTED" : "REJECTED",
         p->yes_votes, p->no_votes);
}

/* -------------------------------------------------------------------------- */
/*                     Event Handlers (Using New Signature)                   */
/* -------------------------------------------------------------------------- */

/**
 * Handler for PROPOSAL_CREATE events.
 */
hc_error_t handle_proposal_create(const char *event_type,
                                   const char *payload,
                                   size_t payload_len,
                                   void *user_context)
{
    (void)event_type;
    (void)payload_len;
    (void)user_context;

    /* Parse the JSON payload to extract id and voting_deadline */
    json_error_t jerr;
    json_t *root = json_loads(payload, 0, &jerr);
    if (!root) {
        LOGW("Failed to parse PROPOSAL_CREATE payload: %s", jerr.text);
        return HC_ERROR_PACK(HC_SUBSYS_GOVERNANCE, HC_SEV_WARNING, HC_EC_DATA_CORRUPT);
    }

    const char *id = json_string_value(json_object_get(root, "id"));
    json_t *deadline_node = json_object_get(root, "voting_deadline");

    if (!id) {
        LOGW("PROPOSAL_CREATE missing 'id' field");
        json_decref(root);
