            "%s.%03ld [%s] %s:%d: ",
            ts_buf, ts.tv_nsec / 1000000,
            log_level_str(lvl),
            file, line);

    va_list ap;
    va_start(ap, fmt);
    vfprintf((lvl >= LOG_ERROR) ? stderr : stdout, fmt, ap);
    va_end(ap);

    fputc('\n', (lvl >= LOG_ERROR) ? stderr : stdout);

    if (lvl == LOG_FATAL) {
        abort();
    }
}

#define LOGD(...) log_internal(LOG_DEBUG, __FILE__, __LINE__, __VA_ARGS__)
#define LOGI(...) log_internal(LOG_INFO,  __FILE__, __LINE__, __VA_ARGS__)
#define LOGW(...) log_internal(LOG_WARN,  __FILE__, __LINE__, __VA_ARGS__)
#define LOGE(...) log_internal(LOG_ERROR, __FILE__, __LINE__, __VA_ARGS__)
#define LOGF(...) log_internal(LOG_FATAL, __FILE__, __LINE__, __VA_ARGS__)

/* -------------------------------------------------------------------------- */
/*                         Governance Proposal State                          */
/* -------------------------------------------------------------------------- */

typedef enum {
    PROPOSAL_DRAFT = 0,
    PROPOSAL_VOTING,
    PROPOSAL_ACCEPTED,
    PROPOSAL_REJECTED,
    PROPOSAL_EXECUTED
} proposal_state_t;

typedef struct governance_proposal {
    char id[64];
    proposal_state_t state;
    uint64_t yes_votes;
    uint64_t no_votes;
    time_t created_at;
    time_t voting_deadline;
    UT_hash_handle hh;
} governance_proposal_t;

/* In-memory key-value store of proposals */
static governance_proposal_t *g_proposals = NULL;
static pthread_rwlock_t g_prop_lock = PTHREAD_RWLOCK_INITIALIZER;

/* Lookup or create a proposal record */
static governance_proposal_t *
proposal_get_or_create(const char *id)
{
    governance_proposal_t *p = NULL;
    pthread_rwlock_rdlock(&g_prop_lock);
    HASH_FIND_STR(g_proposals, id, p);
    pthread_rwlock_unlock(&g_prop_lock);

    if (p) {
        return p;
    }

    pthread_rwlock_wrlock(&g_prop_lock);
    HASH_FIND_STR(g_proposals, id, p);
    if (!p) {
        p = calloc(1, sizeof *p);
        if (!p) {
            pthread_rwlock_unlock(&g_prop_lock);
            LOGE("Memory allocation failed for proposal '%s'", id);
            return NULL;
        }
        strncpy(p->id, id, sizeof p->id - 1);
        p->created_at = time(NULL);
        p->state      = PROPOSAL_DRAFT;
        HASH_ADD_STR(g_proposals, id, p);
        LOGI("Created new proposal %s", id);
    }
    pthread_rwlock_unlock(&g_prop_lock);
    return p;
}

static void proposal_try_finalize(governance_proposal_t *p)
{
    if (p->state != PROPOSAL_VOTING) {
        return;
    }

    time_t now = time(NULL);
    if (now < p->voting_deadline) {
        return;
    }

    p->state = (p->yes_votes > p->no_votes)
                 ? PROPOSAL_ACCEPTED
                 : PROPOSAL_REJECTED;

    LOGI("Proposal %s finalized as %s (yes=%" PRIu64 ", no=%" PRIu64 ")",
         p->id,
         (p->state == PROPOSAL_ACCEPTED) ? "ACCEPTED" : "REJECTED",
         p->yes_votes, p->no_votes);
}

/* -------------------------------------------------------------------------- */
/*                     Event Handlers (Using New Signature)                   */
/* -------------------------------------------------------------------------- */

/**
 * Handler for PROPOSAL_CREATE events.
 */
hc_error_t handle_proposal_create(const char *event_type,
                                   const char *payload,
                                   size_t payload_len,
                                   void *user_context)
{
    (void)event_type;
    (void)payload_len;
    (void)user_context;

    /* Parse the JSON payload to extract id and voting_deadline */
    json_error_t jerr;
    json_t *root = json_loads(payload, 0, &jerr);
    if (!root) {
        LOGW("Failed to parse PROPOSAL_CREATE payload: %s", jerr.text);
        return HC_ERROR_PACK(HC_SUBSYS_GOVERNANCE, HC_SEV_WARNING, HC_EC_DATA_CORRUPT);
    }

    const char *id = json_string_value(json_object_get(root, "id"));
    json_t *deadline_node = json_object_get(root, "voting_deadline");

    if (!id) {
        LOGW("PROPOSAL_CREATE missing 'id' field");
        json_decref(root);
        return HC_ERROR_PACK(HC_SUBSYS_GOVERNANCE, HC_SEV_WARNING, HC_EC_INVALID_ARGUMENT);
    }

    governance_proposal_t *p = proposal_get_or_create(id);
    if (p) {
        p->state = PROPOSAL_VOTING;
        if (json_is_integer(deadline_node)) {
            p->voting_deadline = (time_t)json_integer_value(deadline_node);
        }
        LOGI("Proposal %s entered VOTING state (deadline=%lu)",
             p->id, (unsigned long)p->voting_deadline);
    }

    json_decref(root);
    return HC_OK;
}

/**
 * Handler for VOTE_CAST events.
 */
hc_error_t handle_vote_cast(const char *event_type,
                             const char *payload,
                             size_t payload_len,
                             void *user_context)
{
    (void)event_type;
    (void)payload_len;
    (void)user_context;

    json_error_t jerr;
    json_t *root = json_loads(payload, 0, &jerr);
    if (!root) {
        LOGW("Failed to parse VOTE_CAST payload: %s", jerr.text);
        return HC_ERROR_PACK(HC_SUBSYS_GOVERNANCE, HC_SEV_WARNING, HC_EC_DATA_CORRUPT);
    }

    const char *id = json_string_value(json_object_get(root, "id"));
    const char *vote = json_string_value(json_object_get(root, "vote"));

    if (!id || !vote) {
        LOGW("VOTE_CAST missing required fields");
        json_decref(root);
        return HC_ERROR_PACK(HC_SUBSYS_GOVERNANCE, HC_SEV_WARNING, HC_EC_INVALID_ARGUMENT);
    }

    governance_proposal_t *p = proposal_get_or_create(id);
    if (!p) {
        json_decref(root);
        return HC_ERROR_PACK(HC_SUBSYS_GOVERNANCE, HC_SEV_ERROR, HC_EC_OUT_OF_MEMORY);
    }

    if (p->state != PROPOSAL_VOTING) {
        LOGW("Vote ignored for non-voting proposal %s", p->id);
        json_decref(root);
        return HC_OK;
    }

    bool vote_yes = (strcmp(vote, "yes") == 0);
    if (vote_yes)
        p->yes_votes++;
    else
        p->no_votes++;

    LOGD("Vote registered on %s → yes=%" PRIu64 ", no=%" PRIu64,
         p->id, p->yes_votes, p->no_votes);

    json_decref(root);
    return HC_OK;
}

/**
 * Handler for FINALIZE_REQ events.
 */
hc_error_t handle_finalize_request(const char *event_type,
                                    const char *payload,
                                    size_t payload_len,
                                    void *user_context)
{
    (void)event_type;
    (void)payload_len;
    (void)user_context;

    json_error_t jerr;
    json_t *root = json_loads(payload, 0, &jerr);
    if (!root) {
        LOGW("Failed to parse FINALIZE_REQ payload: %s", jerr.text);
        return HC_ERROR_PACK(HC_SUBSYS_GOVERNANCE, HC_SEV_WARNING, HC_EC_DATA_CORRUPT);
    }

    const char *id = json_string_value(json_object_get(root, "id"));
    if (!id) {
        LOGW("FINALIZE_REQ missing 'id' field");
        json_decref(root);
        return HC_ERROR_PACK(HC_SUBSYS_GOVERNANCE, HC_SEV_WARNING, HC_EC_INVALID_ARGUMENT);
    }

    governance_proposal_t *p = NULL;
    pthread_rwlock_rdlock(&g_prop_lock);
    HASH_FIND_STR(g_proposals, id, p);
    pthread_rwlock_unlock(&g_prop_lock);

    if (!p) {
        LOGW("Finalize requested for unknown proposal %s", id);
    } else {
        proposal_try_finalize(p);
    }

    json_decref(root);
    return HC_OK;
}

/* -------------------------------------------------------------------------- */
/*                             CLI & Bootstrapping                            */
/* -------------------------------------------------------------------------- */

static void load_env_config(void)
{
    const char *lvl = getenv("GOV_HALL_LOG_LEVEL");
    if (lvl) {
        if (strcmp(lvl, "DEBUG") == 0) g_log_level = LOG_DEBUG;
        else if (strcmp(lvl, "INFO") == 0) g_log_level = LOG_INFO;
        else if (strcmp(lvl, "WARN") == 0) g_log_level = LOG_WARN;
        else if (strcmp(lvl, "ERROR") == 0) g_log_level = LOG_ERROR;
        else if (strcmp(lvl, "FATAL") == 0) g_log_level = LOG_FATAL;
    }
}

static void usage(const char *exe)
{
    printf(
        "HoloCanvas Governance Hall %s (built %s)\n\n"
        "Usage: %s [options]\n"
        "Options:\n"
        "  -h, --help            Show this help\n"
        "\n"
        "Environment variables:\n"
        "  GOV_HALL_LOG_LEVEL    DEBUG|INFO|WARN|ERROR|FATAL (default INFO)\n"
        "  GOV_KAFKA_BROKERS     Kafka broker addresses (default: localhost:9092)\n"
        "  GOV_KAFKA_TOPIC       Kafka topic (default: governance-events)\n"
        "  GOV_KAFKA_GROUP_ID    Consumer group ID (default: gov-hall-group)\n",
        GOV_HALL_VERSION, BUILD_TIMESTAMP, exe);
}

static void cleanup_proposals(void)
{
    pthread_rwlock_wrlock(&g_prop_lock);
    governance_proposal_t *curr, *tmp;
    HASH_ITER(hh, g_proposals, curr, tmp) {
        HASH_DEL(g_proposals, curr);
        free(curr);
    }
    pthread_rwlock_unlock(&g_prop_lock);
}

int main(int argc, char **argv)
{
    /* Parse CLI flags */
    for (int i = 1; i < argc; ++i) {
        if (!strcmp(argv[i], "-h") || !strcmp(argv[i], "--help")) {
            usage(argv[0]);
            return EXIT_SUCCESS;
        } else {
            fprintf(stderr, "Unknown option: %s\n", argv[i]);
            usage(argv[0]);
            return EXIT_FAILURE;
        }
    }

    load_env_config();
    LOGI("Starting Governance Hall v%s (%s)", GOV_HALL_VERSION, BUILD_TIMESTAMP);

    /* Get configuration from environment */
    const char *brokers = getenv("GOV_KAFKA_BROKERS");
    const char *topic = getenv("GOV_KAFKA_TOPIC");
    const char *group_id = getenv("GOV_KAFKA_GROUP_ID");

    if (!brokers) brokers = "localhost:9092";
    if (!topic) topic = "governance-events";
    if (!group_id) group_id = "gov-hall-group";

    /* Create the event dispatcher */
    EventDispatcherConfig config = {
        .kafka_brokers = brokers,
        .topic = topic,
        .group_id = group_id,
        .user_context = NULL,
        .poll_timeout_ms = 500,
        .enable_auto_commit = true
    };

    EventDispatcher *dispatcher = event_dispatcher_create(&config);
    if (!dispatcher) {
        LOGE("Failed to create event dispatcher");
        return EXIT_FAILURE;
    }

    /* Register event handlers */
    event_dispatcher_register_handler(dispatcher, "PROPOSAL_CREATE", handle_proposal_create);
    event_dispatcher_register_handler(dispatcher, "VOTE_CAST", handle_vote_cast);
    event_dispatcher_register_handler(dispatcher, "FINALIZE_REQ", handle_finalize_request);

    /* Install signal handlers for graceful shutdown */
    event_dispatcher_install_signal_handlers(dispatcher);

    LOGI("Governance Hall ready, starting event loop...");

    /* Run the event loop (blocks until stopped) */
    event_dispatcher_run(dispatcher);

    /* Cleanup */
    LOGI("Shutting down...");
    event_dispatcher_destroy(dispatcher);
    cleanup_proposals();

    LOGI("Goodbye");
    return EXIT_SUCCESS;
}
