/*
 * HoloCanvas – Mint-Factory Service (Refactored main.c)
 *
 * The Mint-Factory converts "creative recipes" arriving via Kafka into on-chain
 * minting transactions. This refactored version uses the shared EventDispatcher
 * module for Kafka event consumption, eliminating duplicated boilerplate code.
 *
 * Build requirements:
 *   gcc -std=c11 -Wall -Wextra -pedantic -O2 \
 *       -o mint_factory main.c -lpthread -lrdkafka -lcjson -lgrpc -lssl -lcrypto
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdatomic.h>
#include <signal.h>
#include <pthread.h>
#include <errno.h>
#include <time.h>
#include <unistd.h>

#ifndef HOLO_MINT_FACTORY_STUBS
    #include <cjson/cJSON.h>
    #include <librdkafka/rdkafka.h>
    #include <grpc/grpc.h>
#else
    typedef struct cJSON { int dummy; } cJSON;
    static cJSON *cJSON_Parse(const char *s) { (void)s; return NULL; }
    static void cJSON_Delete(cJSON *d) { (void)d; }
    static char *cJSON_PrintUnformatted(const cJSON *d) { (void)d; return strdup("{}"); }
#endif

/* Include the shared event dispatcher */
#include "shared/event_dispatcher/hc_event_dispatcher.h"

/* ------------------------------------------------------------------------- */
/*                            Compile-time Config                            */
/* ------------------------------------------------------------------------- */

#define SERVICE_NAME            "Mint-Factory"
#define DEFAULT_KAFKA_BROKER    "localhost:9092"
#define DEFAULT_KAFKA_TOPIC     "holo.mint.requests"
#define DEFAULT_KAFKA_GROUP_ID  "mint-factory-group"
#define DEFAULT_LEDGER_ENDPOINT "localhost:50051"
#define MAX_ARTIFACT_ID_LEN     64
#define MAX_QUEUE_DEPTH         512
#define MAX_WORKERS             4
#define VERSION_STRING          "1.1.0"

/* ------------------------------------------------------------------------- */
/*                                  Logging                                  */
/* ------------------------------------------------------------------------- */

static pthread_mutex_t log_mtx = PTHREAD_MUTEX_INITIALIZER;

static void log_time(char *buf, size_t sz)
{
    time_t now = time(NULL);
    struct tm tm;
    gmtime_r(&now, &tm);
    strftime(buf, sz, "%Y-%m-%dT%H:%M:%SZ", &tm);
}

#define LOG(level, fmt, ...)                                                       \
    do {                                                                           \
        char _ts[32];                                                              \
        log_time(_ts, sizeof _ts);                                                 \
        pthread_mutex_lock(&log_mtx);                                              \
        fprintf(stderr, "[%s] [%s] [%s] " fmt "\n", _ts, level, SERVICE_NAME,      \
                ##__VA_ARGS__);                                                    \
        pthread_mutex_unlock(&log_mtx);                                            \
    } while (0)

#define LOG_INFO(fmt, ...)   LOG("INFO",  fmt, ##__VA_ARGS__)
#define LOG_WARN(fmt, ...)   LOG("WARN",  fmt, ##__VA_ARGS__)
#define LOG_ERROR(fmt, ...)  LOG("ERROR", fmt, ##__VA_ARGS__)

/* ------------------------------------------------------------------------- */
/*                                Data Models                                */
/* ------------------------------------------------------------------------- */

typedef enum {
    ARTIFACT_DRAFT,
    ARTIFACT_CURATED,
    ARTIFACT_AUCTION,
    ARTIFACT_FRACTIONALIZED,
    ARTIFACT_STAKED
} artifact_state_e;

typedef struct {
    char            id[MAX_ARTIFACT_ID_LEN];
    artifact_state_e state;
    cJSON          *manifest;
    char           *serialized;
} artifact_t;

/* ------------------------------------------------------------------------- */
/*                               Globals & Flags                             */
/* ------------------------------------------------------------------------- */

static atomic_bool g_shutdown_flag = ATOMIC_VAR_INIT(false);

/* ------------------------------------------------------------------------- */
/*                           POSIX Queue (bounded)                           */
/* ------------------------------------------------------------------------- */

typedef struct {
    artifact_t     *buf[MAX_QUEUE_DEPTH];
    size_t          head;
    size_t          tail;
    size_t          count;
    pthread_mutex_t mtx;
    pthread_cond_t  not_empty;
    pthread_cond_t  not_full;
} bqueue_t;

static void bq_init(bqueue_t *q)
{
    memset(q, 0, sizeof *q);
    pthread_mutex_init(&q->mtx, NULL);
    pthread_cond_init(&q->not_empty, NULL);
    pthread_cond_init(&q->not_full, NULL);
}

static void bq_push(bqueue_t *q, artifact_t *item)
{
    pthread_mutex_lock(&q->mtx);
    while (q->count == MAX_QUEUE_DEPTH && !atomic_load(&g_shutdown_flag))
        pthread_cond_wait(&q->not_full, &q->mtx);

    if (atomic_load(&g_shutdown_flag)) { pthread_mutex_unlock(&q->mtx); return; }

    q->buf[q->tail] = item;
    q->tail = (q->tail + 1) % MAX_QUEUE_DEPTH;
    q->count++;
    pthread_cond_signal(&q->not_empty);
    pthread_mutex_unlock(&q->mtx);
}

static artifact_t *bq_pop(bqueue_t *q)
{
    pthread_mutex_lock(&q->mtx);
    while (q->count == 0 && !atomic_load(&g_shutdown_flag))
        pthread_cond_wait(&q->not_empty, &q->mtx);

    artifact_t *item = NULL;
    if (!atomic_load(&g_shutdown_flag) && q->count > 0) {
        item = q->buf[q->head];
        q->head = (q->head + 1) % MAX_QUEUE_DEPTH;
        q->count--;
        pthread_cond_signal(&q->not_full);
    }
    pthread_mutex_unlock(&q->mtx);
    return item;
}

/* ------------------------------------------------------------------------- */
/*                          Configuration Management                         */
/* ------------------------------------------------------------------------- */

typedef struct {
    char kafka_broker[256];
    char kafka_topic[128];
    char kafka_group_id[128];
    char ledger_endpoint[256];
    int  workers;
} config_t;

static void load_config(config_t *cfg)
{
    const char *env;

    strncpy(cfg->kafka_broker,
            (env = getenv("HOLO_KAFKA_BROKER")) ? env : DEFAULT_KAFKA_BROKER,
            sizeof cfg->kafka_broker - 1);

    strncpy(cfg->kafka_topic,
            (env = getenv("HOLO_KAFKA_TOPIC")) ? env : DEFAULT_KAFKA_TOPIC,
            sizeof cfg->kafka_topic - 1);

    strncpy(cfg->kafka_group_id,
            (env = getenv("HOLO_KAFKA_GROUP_ID")) ? env : DEFAULT_KAFKA_GROUP_ID,
            sizeof cfg->kafka_group_id - 1);

    strncpy(cfg->ledger_endpoint,
            (env = getenv("HOLO_LEDGER_ENDPOINT")) ? env : DEFAULT_LEDGER_ENDPOINT,
            sizeof cfg->ledger_endpoint - 1);

    cfg->workers = (env = getenv("HOLO_FACTORY_WORKERS")) ? atoi(env) : MAX_WORKERS;
    if (cfg->workers < 1 || cfg->workers > MAX_WORKERS)
        cfg->workers = MAX_WORKERS;
}

/* ------------------------------------------------------------------------- */
/*                       LedgerCore (gRPC) Integration                       */
/* ------------------------------------------------------------------------- */

static int ledger_send_mint_tx(const artifact_t *a, const config_t *cfg)
{
#ifdef HOLO_MINT_FACTORY_STUBS
    (void)a; (void)cfg;
    LOG_INFO("Stub ledger_send_mint_tx called for artifact %s", a->id);
    return 0;
#else
    (void)cfg;
    LOG_INFO("Sent mint-transaction for artifact %s to ledger", a->id);
    return 0;
#endif
}

/* ------------------------------------------------------------------------- */
/*                      Artifact Assembly && Validation                      */
/* ------------------------------------------------------------------------- */

static int validate_manifest(cJSON *json)
{
    if (!json) return -1;
#ifndef HOLO_MINT_FACTORY_STUBS
    cJSON *artist = cJSON_GetObjectItem(json, "artist_address");
    if (!artist || artist->type != cJSON_String) {
        LOG_WARN("Validation failed – missing/invalid artist_address");
        return -1;
    }
#endif
    return 0;
}

static artifact_t *compose_artifact(const char *payload, size_t len)
{
    (void)len;
    cJSON *json = cJSON_Parse(payload);
    if (!json) {
        LOG_WARN("Invalid JSON in mint request");
        return NULL;
    }
    if (validate_manifest(json) != 0) {
        cJSON_Delete(json);
        return NULL;
    }

    artifact_t *a = calloc(1, sizeof *a);
    if (!a) {
        LOG_ERROR("Memory allocation failed");
        cJSON_Delete(json);
        return NULL;
    }

    unsigned long hash = 5381;
    for (const char *p = payload; *p; ++p) hash = ((hash << 5) + hash) + *p;
    snprintf(a->id, sizeof a->id, "%lx", hash);

    a->state       = ARTIFACT_DRAFT;
    a->manifest    = json;
    a->serialized  = cJSON_PrintUnformatted(json);
    if (!a->serialized) {
        LOG_ERROR("Failed to serialize JSON");
        cJSON_Delete(json);
        free(a);
        return NULL;
    }
    LOG_INFO("Composed artifact %s", a->id);
    return a;
}

static void destroy_artifact(artifact_t *a)
{
    if (!a) return;
    cJSON_Delete(a->manifest);
    free(a->serialized);
    free(a);
}

/* ------------------------------------------------------------------------- */
/*                             Worker Thread Pool                            */
/* ------------------------------------------------------------------------- */

typedef struct {
    bqueue_t   *queue;
    config_t   *cfg;
    int         idx;
} worker_arg_t;

static void *worker_loop(void *arg)
{
    worker_arg_t *wa = arg;
    LOG_INFO("Worker-%d online", wa->idx);

    while (!atomic_load(&g_shutdown_flag)) {
        artifact_t *a = bq_pop(wa->queue);
        if (!a) continue;

        sleep(1);  /* Simulate on-chain commit latency */

        if (ledger_send_mint_tx(a, wa->cfg) == 0) {
            LOG_INFO("Artifact %s minted successfully", a->id);
        } else {
            LOG_WARN("Ledger commit failed for artifact %s", a->id);
        }

        destroy_artifact(a);
    }
    LOG_INFO("Worker-%d shutting down", wa->idx);
    return NULL;
}

/* ------------------------------------------------------------------------- */
/*                     Event Handlers (New Dispatcher API)                   */
/* ------------------------------------------------------------------------- */

typedef struct {
    bqueue_t *queue;
    config_t *cfg;
} service_context_t;

/**
 * Handler for MINT_REQUEST events.
 */
hc_error_t handle_mint_request(const char *event_type,
                                const char *payload,
                                size_t payload_len,
                                void *user_context)
{
    (void)event_type;
    service_context_t *ctx = (service_context_t *)user_context;

    LOG_INFO("Processing MINT_REQUEST event");

    artifact_t *a = compose_artifact(payload, payload_len);
    if (a) {
        bq_push(ctx->queue, a);
    }

    return HC_OK;
}

/**
 * Handler for BID events.
 */
hc_error_t handle_bid(const char *event_type,
                       const char *payload,
                       size_t payload_len,
                       void *user_context)
{
    (void)event_type;
    (void)payload_len;
    (void)user_context;

    LOG_INFO("Processing BID event: %s", payload);
    /* TODO: Implement bid handling logic */
    return HC_OK;
}

/**
 * Handler for GOVERNANCE_VOTE events.
 */
hc_error_t handle_governance_vote(const char *event_type,
                                   const char *payload,
                                   size_t payload_len,
                                   void *user_context)
{
    (void)event_type;
    (void)payload_len;
    (void)user_context;

    LOG_INFO("Processing GOVERNANCE_VOTE event: %s", payload);
    /* TODO: Implement governance vote handling */
    return HC_OK;
}

/**
 * Handler for ORACLE_FEED events.
 */
hc_error_t handle_oracle_feed(const char *event_type,
                               const char *payload,
                               size_t payload_len,
                               void *user_context)
{
    (void)event_type;
    (void)payload_len;
    (void)user_context;

    LOG_INFO("Processing ORACLE_FEED event: %s", payload);
    /* TODO: Implement oracle feed handling */
    return HC_OK;
}

/* ------------------------------------------------------------------------- */
/*                                   Main                                    */
/* ------------------------------------------------------------------------- */

int main(void)
{
    LOG_INFO("Starting %s v%s", SERVICE_NAME, VERSION_STRING);

    config_t cfg;
    load_config(&cfg);
    LOG_INFO("Config: Kafka[%s/%s] Ledger[%s] Workers[%d]",
             cfg.kafka_broker, cfg.kafka_topic,
             cfg.ledger_endpoint, cfg.workers);

    bqueue_t queue;
    bq_init(&queue);

    /* Create service context for handlers */
    service_context_t svc_ctx = {
        .queue = &queue,
        .cfg = &cfg
    };

    /* Create the event dispatcher */
    EventDispatcherConfig disp_config = {
        .kafka_brokers = cfg.kafka_broker,
        .topic = cfg.kafka_topic,
