    bqueue_t *queue;
    config_t *cfg;
} service_context_t;

/**
 * Handler for MINT_REQUEST events.
 */
hc_error_t handle_mint_request(const char *event_type,
                                const char *payload,
                                size_t payload_len,
                                void *user_context)
{
    (void)event_type;
    service_context_t *ctx = (service_context_t *)user_context;

    LOG_INFO("Processing MINT_REQUEST event");

    artifact_t *a = compose_artifact(payload, payload_len);
    if (a) {
        bq_push(ctx->queue, a);
    }

    return HC_OK;
}

