/* ------------------------------------------------------------------------- */

int main(void)
{
    LOG_INFO("Starting %s v%s", SERVICE_NAME, VERSION_STRING);

    config_t cfg;
    load_config(&cfg);
    LOG_INFO("Config: Kafka[%s/%s] Ledger[%s] Workers[%d]",
             cfg.kafka_broker, cfg.kafka_topic,
             cfg.ledger_endpoint, cfg.workers);

    bqueue_t queue;
    bq_init(&queue);

