    event_dispatcher_register_handler(dispatcher, "ORACLE_FEED", handle_oracle_feed);

    /* Install signal handlers */
    event_dispatcher_install_signal_handlers(dispatcher);

    /* Spawn worker threads */
    pthread_t workers[MAX_WORKERS];
    worker_arg_t warg[MAX_WORKERS];
    for (int i = 0; i < cfg.workers; ++i) {
        warg[i].queue = &queue;
        warg[i].cfg   = &cfg;
        warg[i].idx   = i;
        if (pthread_create(&workers[i], NULL, worker_loop, &warg[i]) != 0) {
