    if (validate_manifest(json) != 0) {
        cJSON_Delete(json);
        return NULL;
    }

    artifact_t *a = calloc(1, sizeof *a);
    if (!a) {
        LOG_ERROR("Memory allocation failed");
        cJSON_Delete(json);
        return NULL;
    }

    unsigned long hash = 5381;
    for (const char *p = payload; *p; ++p) hash = ((hash << 5) + hash) + *p;
    snprintf(a->id, sizeof a->id, "%lx", hash);

    a->state       = ARTIFACT_DRAFT;
    a->manifest    = json;
    a->serialized  = cJSON_PrintUnformatted(json);
    if (!a->serialized) {
        LOG_ERROR("Failed to serialize JSON");
        cJSON_Delete(json);
        free(a);
        return NULL;
    }
    LOG_INFO("Composed artifact %s", a->id);
    return a;
}

static void destroy_artifact(artifact_t *a)
{
    if (!a) return;
    cJSON_Delete(a->manifest);
    free(a->serialized);
    free(a);
}

/* ------------------------------------------------------------------------- */
/*                             Worker Thread Pool                            */
/* ------------------------------------------------------------------------- */

typedef struct {
    bqueue_t   *queue;
    config_t   *cfg;
    int         idx;
} worker_arg_t;

static void *worker_loop(void *arg)
{
    worker_arg_t *wa = arg;
    LOG_INFO("Worker-%d online", wa->idx);

    while (!atomic_load(&g_shutdown_flag)) {
        artifact_t *a = bq_pop(wa->queue);
        if (!a) continue;

        sleep(1);  /* Simulate on-chain commit latency */

        if (ledger_send_mint_tx(a, wa->cfg) == 0) {
            LOG_INFO("Artifact %s minted successfully", a->id);
        } else {
            LOG_WARN("Ledger commit failed for artifact %s", a->id);
        }

        destroy_artifact(a);
    }
    LOG_INFO("Worker-%d shutting down", wa->idx);
    return NULL;
}

/* ------------------------------------------------------------------------- */
/*                     Event Handlers (New Dispatcher API)                   */
/* ------------------------------------------------------------------------- */

typedef struct {
    bqueue_t *queue;
    config_t *cfg;
} service_context_t;

/**
 * Handler for MINT_REQUEST events.
 */
hc_error_t handle_mint_request(const char *event_type,
                                const char *payload,
                                size_t payload_len,
                                void *user_context)
{
    (void)event_type;
    service_context_t *ctx = (service_context_t *)user_context;

    LOG_INFO("Processing MINT_REQUEST event");

    artifact_t *a = compose_artifact(payload, payload_len);
    if (a) {
        bq_push(ctx->queue, a);
    }

    return HC_OK;
}

/**
 * Handler for BID events.
 */
hc_error_t handle_bid(const char *event_type,
                       const char *payload,
                       size_t payload_len,
                       void *user_context)
{
    (void)event_type;
    (void)payload_len;
    (void)user_context;

    LOG_INFO("Processing BID event: %s", payload);
    /* TODO: Implement bid handling logic */
    return HC_OK;
}

/**
 * Handler for GOVERNANCE_VOTE events.
 */
hc_error_t handle_governance_vote(const char *event_type,
                                   const char *payload,
                                   size_t payload_len,
                                   void *user_context)
{
    (void)event_type;
    (void)payload_len;
    (void)user_context;

    LOG_INFO("Processing GOVERNANCE_VOTE event: %s", payload);
    /* TODO: Implement governance vote handling */
    return HC_OK;
}

/**
 * Handler for ORACLE_FEED events.
 */
hc_error_t handle_oracle_feed(const char *event_type,
                               const char *payload,
                               size_t payload_len,
                               void *user_context)
{
    (void)event_type;
    (void)payload_len;
    (void)user_context;

    LOG_INFO("Processing ORACLE_FEED event: %s", payload);
    /* TODO: Implement oracle feed handling */
    return HC_OK;
}

/* ------------------------------------------------------------------------- */
/*                                   Main                                    */
/* ------------------------------------------------------------------------- */

int main(void)
{
    LOG_INFO("Starting %s v%s", SERVICE_NAME, VERSION_STRING);

    config_t cfg;
    load_config(&cfg);
    LOG_INFO("Config: Kafka[%s/%s] Ledger[%s] Workers[%d]",
             cfg.kafka_broker, cfg.kafka_topic,
             cfg.ledger_endpoint, cfg.workers);

    bqueue_t queue;
    bq_init(&queue);

    /* Create service context for handlers */
    service_context_t svc_ctx = {
        .queue = &queue,
        .cfg = &cfg
    };

    /* Create the event dispatcher */
    EventDispatcherConfig disp_config = {
        .kafka_brokers = cfg.kafka_broker,
        .topic = cfg.kafka_topic,
        .group_id = cfg.kafka_group_id,
        .user_context = &svc_ctx,
        .poll_timeout_ms = 250,
        .enable_auto_commit = true
    };

    EventDispatcher *dispatcher = event_dispatcher_create(&disp_config);
    if (!dispatcher) {
        LOG_ERROR("Failed to create event dispatcher");
        return EXIT_FAILURE;
    }

    /* Register event handlers */
    event_dispatcher_register_handler(dispatcher, "MINT_REQUEST", handle_mint_request);
    event_dispatcher_register_handler(dispatcher, "BID", handle_bid);
    event_dispatcher_register_handler(dispatcher, "GOVERNANCE_VOTE", handle_governance_vote);
    event_dispatcher_register_handler(dispatcher, "ORACLE_FEED", handle_oracle_feed);

    /* Install signal handlers */
    event_dispatcher_install_signal_handlers(dispatcher);

    /* Spawn worker threads */
    pthread_t workers[MAX_WORKERS];
    worker_arg_t warg[MAX_WORKERS];
    for (int i = 0; i < cfg.workers; ++i) {
        warg[i].queue = &queue;
        warg[i].cfg   = &cfg;
        warg[i].idx   = i;
        if (pthread_create(&workers[i], NULL, worker_loop, &warg[i]) != 0) {
            LOG_ERROR("Failed to create worker thread");
            atomic_store(&g_shutdown_flag, true);
            break;
        }
    }

    LOG_INFO("Mint-Factory ready, starting event loop...");

    /* Run the event loop (blocks until stopped) */
    event_dispatcher_run(dispatcher);

    /* Shutdown sequence */
    LOG_INFO("Shutdown requested – waiting for threads");
    atomic_store(&g_shutdown_flag, true);

    /* Wake queues and join threads */
    pthread_mutex_lock(&queue.mtx);
    pthread_cond_broadcast(&queue.not_empty);
    pthread_cond_broadcast(&queue.not_full);
    pthread_mutex_unlock(&queue.mtx);

    for (int i = 0; i < cfg.workers; ++i) {
        pthread_join(workers[i], NULL);
    }

    event_dispatcher_destroy(dispatcher);

    LOG_INFO("%s terminated gracefully", SERVICE_NAME);
    return 0;
}
