/*
 * HoloCanvas — Muse Observer Service (Refactored)
 * ------------------------------------------------
 * File: services/muse_observer/src/main.c
 *
 * Description:
 *   The Muse-Observer is an event-driven micro-service that listens to the
 *   HoloCanvas Kafka mesh for artistic triggers. This refactored version uses
 *   the shared EventDispatcher module for Kafka event consumption, eliminating
 *   duplicated boilerplate code.
 *
 * Build:
 *   cc -std=c11 -Wall -Wextra -Werror \
 *      -o muse_observer main.c -lrdkafka -ldl -ljansson -lpthread
 *
 * Copyright:
 *   © 2024 HoloCanvas Contributors. Licensed under the Apache-2.0 license.
 */

#define _GNU_SOURCE
#include <errno.h>
#include <getopt.h>
#include <jansson.h>
#include <signal.h>
#include <stdbool.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <syslog.h>
#include <unistd.h>
#include <dlfcn.h>

/* Include the shared event dispatcher */
#include "shared/event_dispatcher/hc_event_dispatcher.h"

/* ------------------------------------------------------------------------- */
/* Constants & Macros                                                        */
/* ------------------------------------------------------------------------- */
#define MUSE_VERSION      "2.0.0"
#define DEFAULT_BROKERS   "localhost:9092"
#define DEFAULT_TOPIC     "holo.events"
#define DEFAULT_GROUP_ID  "muse-observer-group"
#define DEFAULT_PLUGDIR   "/usr/local/lib/holo/plugins"
#define DEFAULT_GRPC_TGT  "localhost:50051"
#define MAX_PLUGIN_NAME   128

#define LOG(level, fmt, ...) \
    syslog(level, "[muse] " fmt, ##__VA_ARGS__)

#define DIE(fmt, ...)                        \
    do {                                     \
        LOG(LOG_ERR, fmt, ##__VA_ARGS__);    \
        exit(EXIT_FAILURE);                  \
    } while (0)

/* ------------------------------------------------------------------------- */
/* Configuration Structure                                                   */
/* ------------------------------------------------------------------------- */
typedef struct {
    char *kafka_brokers;
    char *topic;
    char *group_id;
    char *plugin_dir;
    char *grpc_target;
    int   verbosity;
} muse_cfg_t;

/* ------------------------------------------------------------------------- */
/* Strategy Plug-in Interface                                                */
/* ------------------------------------------------------------------------- */
typedef int (*strategy_fn)(const char *event_json, char **out_recipe_json);
typedef int (*strategy_init_fn)(void);
typedef void (*strategy_fini_fn)(void);

typedef struct {
    char          name[MAX_PLUGIN_NAME];
    void         *dl_handle;
    strategy_fn   run;
    strategy_fini_fn fini;
} plugin_t;

/* Global plugin cache */
static plugin_t g_plugin_cache = {0};

/* ------------------------------------------------------------------------- */
/* Utility                                                                   */
/* ------------------------------------------------------------------------- */
static char *dup_or_default(const char *src, const char *def) {
    return strdup(src && *src ? src : def);
}

/* ------------------------------------------------------------------------- */
/* Command-line / Environment Parsing                                        */
/* ------------------------------------------------------------------------- */
static void muse_parse_cli(int argc, char **argv, muse_cfg_t *cfg) {
    static struct option long_opts[] = {
        { "brokers",     required_argument, 0, 'b' },
        { "topic",       required_argument, 0, 't' },
        { "group-id",    required_argument, 0, 'G' },
        { "plugin-dir",  required_argument, 0, 'p' },
        { "grpc",        required_argument, 0, 'g' },
        { "verbose",     no_argument,       0, 'v' },
        { "version",     no_argument,       0, 'V' },
        { "help",        no_argument,       0, 'h' },
        { 0,             0,                 0,  0  }
    };

    int opt;
    while ((opt = getopt_long(argc, argv, "b:t:G:p:g:vVh", long_opts, NULL)) != -1) {
        switch (opt) {
        case 'b': free(cfg->kafka_brokers); cfg->kafka_brokers = strdup(optarg); break;
        case 't': free(cfg->topic);         cfg->topic        = strdup(optarg);  break;
        case 'G': free(cfg->group_id);      cfg->group_id     = strdup(optarg);  break;
        case 'p': free(cfg->plugin_dir);    cfg->plugin_dir   = strdup(optarg);  break;
        case 'g': free(cfg->grpc_target);   cfg->grpc_target  = strdup(optarg);  break;
        case 'v': cfg->verbosity++;                                              break;
        case 'V':
            printf("Muse Observer v%s\n", MUSE_VERSION);
            exit(EXIT_SUCCESS);
        case 'h':
        default:
            printf("Usage: %s [options]\n"
                   "  -b, --brokers    Kafka bootstrap servers (default: %s)\n"
                   "  -t, --topic      Kafka topic to consume   (default: %s)\n"
                   "  -G, --group-id   Kafka consumer group     (default: %s)\n"
                   "  -p, --plugin-dir Directory containing strategy plug-ins\n"
                   "                   (default: %s)\n"
                   "  -g, --grpc       Mint-Factory gRPC target (default: %s)\n"
                   "  -v, --verbose    Increase verbosity (can repeat)\n"
                   "  -V, --version    Show version\n"
                   "  -h, --help       Show this help message\n",
                   argv[0], DEFAULT_BROKERS, DEFAULT_TOPIC, DEFAULT_GROUP_ID,
                   DEFAULT_PLUGDIR, DEFAULT_GRPC_TGT);
            exit(opt == 'h' ? EXIT_SUCCESS : EXIT_FAILURE);
        }
    }
}

/* ------------------------------------------------------------------------- */
/* Plug-in Loader                                                            */
/* ------------------------------------------------------------------------- */
static int plugin_open(plugin_t *plg, const char *plugin_dir, const char *strategy_name)
{
    snprintf(plg->name, sizeof(plg->name), "%s", strategy_name);

    char *so_path;
    if (asprintf(&so_path, "%s/lib%s.so", plugin_dir, strategy_name) < 0)
        return -1;

    plg->dl_handle = dlopen(so_path, RTLD_NOW | RTLD_LOCAL);
    free(so_path);

    if (!plg->dl_handle) {
        LOG(LOG_ERR, "dlopen failed for strategy `%s`: %s", strategy_name, dlerror());
        return -1;
    }

    plg->run = (strategy_fn)dlsym(plg->dl_handle, "muse_strategy_run");
    if (!plg->run) {
        LOG(LOG_ERR, "Plug-in `%s` missing muse_strategy_run symbol", strategy_name);
        dlclose(plg->dl_handle);
        return -1;
    }

    strategy_init_fn init_fn = (strategy_init_fn)dlsym(plg->dl_handle, "muse_strategy_init");
    if (init_fn && init_fn() != 0) {
        LOG(LOG_ERR, "Plug-in `%s` failed to initialize", strategy_name);
        dlclose(plg->dl_handle);
        return -1;
    }

    plg->fini = (strategy_fini_fn)dlsym(plg->dl_handle, "muse_strategy_fini");
    LOG(LOG_INFO, "Loaded strategy `%s`", strategy_name);
    return 0;
}

static void plugin_close(plugin_t *plg) {
    if (!plg || !plg->dl_handle) return;
    if (plg->fini) plg->fini();
    dlclose(plg->dl_handle);
    plg->dl_handle = NULL;
    memset(plg->name, 0, sizeof(plg->name));
}

/* ------------------------------------------------------------------------- */
/* gRPC Mint-Factory Client (stub)                                           */
/* ------------------------------------------------------------------------- */
static int grpc_send_evolution(const char *grpc_target, const char *recipe_json)
{
    (void)grpc_target;
    LOG(LOG_INFO, "Stub gRPC call sent to Mint-Factory: %s", recipe_json);
    return 0;
}

/* ------------------------------------------------------------------------- */
/* Service Context                                                           */
/* ------------------------------------------------------------------------- */
typedef struct {
    muse_cfg_t *cfg;
    plugin_t   *plugin_cache;
} muse_context_t;

/* ------------------------------------------------------------------------- */
/* Event Handlers (New Dispatcher API)                                       */
/* ------------------------------------------------------------------------- */

/**
 * Generic event handler that dispatches to the appropriate strategy plugin.
 * The strategy is selected based on the "strategy" field in the JSON payload.
 */
hc_error_t handle_muse_event(const char *event_type,
                              const char *payload,
                              size_t payload_len,
                              void *user_context)
{
    (void)event_type;
    (void)payload_len;

    muse_context_t *ctx = (muse_context_t *)user_context;
    if (!ctx || !ctx->cfg) {
        return HC_ERROR_PACK(HC_SUBSYS_COMMON, HC_SEV_ERROR, HC_EC_INVALID_ARGUMENT);
    }

    /* Parse JSON to find strategy */
    json_error_t jerr;
    json_t *root = json_loads(payload, 0, &jerr);
    if (!root) {
        LOG(LOG_WARNING, "Invalid JSON payload: %s", jerr.text);
        return HC_ERROR_PACK(HC_SUBSYS_COMMON, HC_SEV_WARNING, HC_EC_DATA_CORRUPT);
    }

    const char *strategy = json_string_value(json_object_get(root, "strategy"));
    if (!strategy) {
        LOG(LOG_INFO, "No strategy specified; ignoring event");
        json_decref(root);
        return HC_OK;
    }

    LOG(LOG_INFO, "Received event type '%s' with strategy '%s'", event_type, strategy);

    /* Caching: if last loaded plugin matches, reuse it */
    plugin_t plg = {0};
    plugin_t *use = &plg;

    if (ctx->plugin_cache &&
        strcmp(ctx->plugin_cache->name, strategy) == 0 &&
        ctx->plugin_cache->dl_handle) {
        use = ctx->plugin_cache;
    } else {
        /* Unload previous */
        if (ctx->plugin_cache && ctx->plugin_cache->dl_handle)
            plugin_close(ctx->plugin_cache);

        /* Load new */
        if (plugin_open(&plg, ctx->cfg->plugin_dir, strategy) != 0) {
            json_decref(root);
            return HC_ERROR_PACK(HC_SUBSYS_COMMON, HC_SEV_ERROR, HC_EC_DEPENDENCY_FAILURE);
        }
    }

    /* Call strategy */
    char *recipe_json = NULL;
    int rc = use->run(payload, &recipe_json);
    if (rc != 0 || !recipe_json) {
        LOG(LOG_ERR, "Strategy `%s` failed (rc=%d)", strategy, rc);
        json_decref(root);
        if (use == &plg) plugin_close(&plg);
        return HC_ERROR_PACK(HC_SUBSYS_COMMON, HC_SEV_ERROR, HC_EC_DEPENDENCY_FAILURE);
    }

    /* Send evolution to Mint-Factory */
    rc = grpc_send_evolution(ctx->cfg->grpc_target, recipe_json);
    free(recipe_json);

    /* Cache plugin for reuse */
    if (use == &plg && rc == 0 && ctx->plugin_cache) {
        *ctx->plugin_cache = plg;
    } else if (use == &plg) {
        plugin_close(&plg);
    }

    json_decref(root);
    return rc == 0 ? HC_OK : HC_ERROR_PACK(HC_SUBSYS_COMMON, HC_SEV_ERROR, HC_EC_NETWORK_UNREACHABLE);
}

/**
 * Handler for ARTISTIC_TRIGGER events.
 */
hc_error_t handle_artistic_trigger(const char *event_type,
                                    const char *payload,
                                    size_t payload_len,
                                    void *user_context)
{
    return handle_muse_event(event_type, payload, payload_len, user_context);
}

/**
 * Handler for ORACLE_UPDATE events.
 */
hc_error_t handle_oracle_update(const char *event_type,
                                 const char *payload,
                                 size_t payload_len,
                                 void *user_context)
{
    return handle_muse_event(event_type, payload, payload_len, user_context);
}

/**
 * Handler for DAO_VOTE events.
 */
hc_error_t handle_dao_vote(const char *event_type,
                            const char *payload,
                            size_t payload_len,
                            void *user_context)
{
    return handle_muse_event(event_type, payload, payload_len, user_context);
}

/**
 * Handler for LIKE_RECEIVED events.
 */
hc_error_t handle_like_received(const char *event_type,
                                 const char *payload,
                                 size_t payload_len,
                                 void *user_context)
{
    return handle_muse_event(event_type, payload, payload_len, user_context);
}

/* ------------------------------------------------------------------------- */
/* Entry Point                                                               */
/* ------------------------------------------------------------------------- */
int main(int argc, char **argv)
{
    openlog("holo-muse", LOG_PID | LOG_CONS, LOG_DAEMON);

    muse_cfg_t cfg = {
        .kafka_brokers = dup_or_default(getenv("MUSE_KAFKA_BROKERS"), DEFAULT_BROKERS),
        .topic         = dup_or_default(getenv("MUSE_TOPIC"), DEFAULT_TOPIC),
        .group_id      = dup_or_default(getenv("MUSE_GROUP_ID"), DEFAULT_GROUP_ID),
        .plugin_dir    = dup_or_default(getenv("MUSE_PLUGIN_DIR"), DEFAULT_PLUGDIR),
        .grpc_target   = dup_or_default(getenv("MUSE_GRPC_TARGET"), DEFAULT_GRPC_TGT),
        .verbosity     = 0
    };

    muse_parse_cli(argc, argv, &cfg);

    /* Adjust syslog verbosity */
    setlogmask(LOG_UPTO(cfg.verbosity ? LOG_DEBUG : LOG_INFO));

    LOG(LOG_INFO, "Muse Observer v%s starting...", MUSE_VERSION);
    LOG(LOG_INFO, "Config: brokers=%s, topic=%s, group=%s",
        cfg.kafka_brokers, cfg.topic, cfg.group_id);

    /* Create service context */
    muse_context_t muse_ctx = {
        .cfg = &cfg,
        .plugin_cache = &g_plugin_cache
    };

    /* Create the event dispatcher */
    EventDispatcherConfig disp_config = {
        .kafka_brokers = cfg.kafka_brokers,
        .topic = cfg.topic,
        .group_id = cfg.group_id,
        .user_context = &muse_ctx,
        .poll_timeout_ms = 500,
        .enable_auto_commit = true
    };

    EventDispatcher *dispatcher = event_dispatcher_create(&disp_config);
    if (!dispatcher) {
        DIE("Failed to create event dispatcher");
    }

    /* Register event handlers for all event types we care about */
    event_dispatcher_register_handler(dispatcher, "ARTISTIC_TRIGGER", handle_artistic_trigger);
    event_dispatcher_register_handler(dispatcher, "ORACLE_UPDATE", handle_oracle_update);
    event_dispatcher_register_handler(dispatcher, "DAO_VOTE", handle_dao_vote);
    event_dispatcher_register_handler(dispatcher, "LIKE_RECEIVED", handle_like_received);

    /* Install signal handlers */
    event_dispatcher_install_signal_handlers(dispatcher);

    LOG(LOG_INFO, "Muse Observer ready, starting event loop...");

    /* Run the event loop (blocks until stopped) */
    event_dispatcher_run(dispatcher);

    /* Cleanup */
    LOG(LOG_INFO, "Shutting down...");

    if (g_plugin_cache.dl_handle)
        plugin_close(&g_plugin_cache);

    event_dispatcher_destroy(dispatcher);

    free(cfg.kafka_brokers);
    free(cfg.topic);
    free(cfg.group_id);
    free(cfg.plugin_dir);
    free(cfg.grpc_target);

    closelog();
    LOG(LOG_INFO, "Muse Observer terminated gracefully");
    return EXIT_SUCCESS;
}

